const PHYSICS_AQA_PRACTICE = {
  '3.1': {
    name: 'Measurements and Their Errors',
    questions: [
      { q: 'State the SI base units for mass, length, and time.', marks: 1, markScheme: '• kg, m, s (1)' },
      { q: 'State the SI base unit for temperature.', marks: 1, markScheme: '• kelvin (K) (1)' },
      { q: 'State the SI base unit for electric current.', marks: 1, markScheme: '• ampere (A) (1)' },
      { q: 'State the SI base unit for amount of substance.', marks: 1, markScheme: '• mole (mol) (1)' },
      { q: 'Express the unit of force (newton) in SI base units.', marks: 1, markScheme: '• kg m s⁻² (1)' },
      { q: 'Express the unit of energy (joule) in SI base units.', marks: 1, markScheme: '• kg m² s⁻² (1)' },
      { q: 'Express the unit of pressure (pascal) in SI base units.', marks: 1, markScheme: '• kg m⁻¹ s⁻² (1)' },
      { q: 'Express the unit of power (watt) in SI base units.', marks: 1, markScheme: '• kg m² s⁻³ (1)' },
      { q: 'What is the value of the prefix "nano"?', marks: 1, markScheme: '• 10⁻⁹ (1)' },
      { q: 'What is the value of the prefix "giga"?', marks: 1, markScheme: '• 10⁹ (1)' },
      { q: 'Convert 4.7 μm to metres.', marks: 1, markScheme: '• 4.7 × 10⁻⁶ m (1)' },
      { q: 'Define the term "systematic error".', marks: 2, markScheme: '• An error that is the same for every reading/measurement (1)\n• Caused by faulty equipment or flawed experimental design (1)' },
      { q: 'Define the term "random error".', marks: 2, markScheme: '• An error that causes readings to scatter around the true value (1)\n• Can be reduced by taking repeat readings and averaging (1)' },
      { q: 'Distinguish between accuracy and precision.', marks: 2, markScheme: '• Accuracy: how close a measurement is to the true value (1)\n• Precision: how close repeated measurements are to each other / small spread of results (1)' },
      { q: 'A student measures the diameter of a wire as 0.52 ± 0.01 mm. Calculate the percentage uncertainty in this measurement.', marks: 2, markScheme: '• % uncertainty = (0.01 / 0.52) × 100 (1)\n• = 1.9% (1)' },
      { q: 'The length of a rod is measured as 1.50 ± 0.02 m. Calculate the percentage uncertainty in the area of the cross-section if it is square.', marks: 2, markScheme: '• Area = length², so % uncertainty in area = 2 × % uncertainty in length (1)\n• = 2 × (0.02/1.50) × 100 = 2.7% (1)' },
      { q: 'A force of 25 ± 1 N is applied over an area of 0.050 ± 0.005 m². Calculate the percentage uncertainty in the calculated pressure.', marks: 3, markScheme: '• % uncertainty in F = (1/25) × 100 = 4.0% (1)\n• % uncertainty in A = (0.005/0.050) × 100 = 10% (1)\n• Total % uncertainty = 4.0 + 10 = 14% (1)' },
      { q: 'Explain how a student could reduce the uncertainty when timing 20 oscillations of a pendulum.', marks: 3, markScheme: '• Use a fiducial marker at the equilibrium position (1)\n• Time a larger number of oscillations (e.g. 50) and divide (1)\n• Take repeat readings and calculate a mean (1)' },
      { q: 'The speed of a car is calculated from distance ÷ time. The distance is 100 ± 2 m and the time is 8.0 ± 0.5 s. Calculate the speed and its absolute uncertainty.', marks: 4, markScheme: '• Speed = 100 / 8.0 = 12.5 m s⁻¹ (1)\n• % uncertainty in distance = (2/100) × 100 = 2% (1)\n• % uncertainty in time = (0.5/8.0) × 100 = 6.25% (1)\n• Absolute uncertainty = 8.25% of 12.5 = ±1.0 m s⁻¹, so speed = 12.5 ± 1.0 m s⁻¹ (1)' },
      { q: 'State what is meant by the resolution of a measuring instrument.', marks: 1, markScheme: '• The smallest change in the quantity being measured that gives a recognisable change in reading (1)' },
      { q: 'A student plots a graph and draws a line of best fit and a worst acceptable line. Explain how these can be used to determine the uncertainty in the gradient.', marks: 3, markScheme: '• Draw the steepest or shallowest line that still passes through the error bars (1)\n• Calculate the gradient of the best fit line and the worst line (1)\n• Uncertainty in gradient = |gradient of best fit − gradient of worst line| (1)' },
      { q: 'Express the unit of electrical resistance (ohm) in SI base units.', marks: 2, markScheme: '• R = V/I, and V = W/A = kg m² s⁻³ A⁻¹ (1)\n• Ω = kg m² s⁻³ A⁻² (1)' },
      { q: 'Explain the difference between a zero error and a parallax error.', marks: 2, markScheme: '• Zero error: instrument does not read zero when it should / systematic (1)\n• Parallax error: reading changes depending on the angle of observation / random error in reading scales (1)' },
      { q: 'The period T of a pendulum is related to length L by T = 2π√(L/g). A student measures T = 1.40 ± 0.02 s and L = 0.490 ± 0.005 m. Calculate g and its percentage uncertainty.', marks: 4, markScheme: '• g = 4π²L/T² = 4π² × 0.490 / 1.40² = 9.85 m s⁻² (1)\n• % uncertainty in L = (0.005/0.490) × 100 = 1.0% (1)\n• % uncertainty in T² = 2 × (0.02/1.40) × 100 = 2.9% (1)\n• Total % uncertainty in g = 1.0 + 2.9 = 3.9% (1)' },
      { q: 'State what is meant by a "vernier scale" and give its typical resolution when used on callipers.', marks: 2, markScheme: '• A secondary scale that allows interpolation between divisions on the main scale (1)\n• Typical resolution of vernier callipers is 0.01 mm or 0.02 mm (1)' }
    ]
  },
  '3.2': {
    name: 'Particles and Radiation',
    questions: [
      { q: 'State the three types of particle that make up an atom.', marks: 1, markScheme: '• Protons, neutrons, and electrons (1)' },
      { q: 'State the quark composition of a proton.', marks: 1, markScheme: '• uud (up, up, down) (1)' },
      { q: 'State the quark composition of a neutron.', marks: 1, markScheme: '• udd (up, down, down) (1)' },
      { q: 'State the charge and baryon number of an up quark.', marks: 1, markScheme: '• Charge = +⅔ e, baryon number = +⅓ (1)' },
      { q: 'State the charge and baryon number of a down quark.', marks: 1, markScheme: '• Charge = −⅓ e, baryon number = +⅓ (1)' },
      { q: 'Define the term "lepton".', marks: 2, markScheme: '• A fundamental particle (1)\n• That does not experience the strong nuclear force (1)' },
      { q: 'Name the four fundamental forces and state which has the longest range.', marks: 2, markScheme: '• Strong nuclear, weak nuclear, electromagnetic, gravitational (1)\n• Gravitational has infinite range (1)' },
      { q: 'State what is meant by an antiparticle and give one example.', marks: 2, markScheme: '• A particle with the same mass as its corresponding particle but opposite charge and quantum numbers (1)\n• Example: positron (anti-electron), antiproton, antineutrino (1)' },
      { q: 'Describe what happens during pair production.', marks: 2, markScheme: '• A photon of sufficient energy converts into a particle-antiparticle pair (1)\n• The photon must have energy ≥ 2mc² where m is the rest mass of one of the particles (1)' },
      { q: 'Describe what happens during annihilation.', marks: 2, markScheme: '• A particle meets its antiparticle (1)\n• They are destroyed and their mass is converted into two photons travelling in opposite directions (1)' },
      { q: 'Calculate the minimum photon energy required for electron-positron pair production. (Mass of electron = 9.11 × 10⁻³¹ kg, c = 3.00 × 10⁸ m s⁻¹)', marks: 2, markScheme: '• E = 2mc² = 2 × 9.11 × 10⁻³¹ × (3.00 × 10⁸)² (1)\n• E = 1.64 × 10⁻¹³ J (or 1.02 MeV) (1)' },
      { q: 'State the exchange particle for the electromagnetic force.', marks: 1, markScheme: '• Virtual photon (1)' },
      { q: 'State the exchange particle for the weak nuclear force.', marks: 1, markScheme: '• W⁺, W⁻ or Z⁰ boson (1)' },
      { q: 'State the exchange particle for the strong nuclear force between nucleons.', marks: 1, markScheme: '• Pion (π meson) (1)' },
      { q: 'Explain why a free neutron can decay but a neutron inside a stable nucleus does not.', marks: 3, markScheme: '• A free neutron undergoes beta-minus decay: n → p + e⁻ + ν̄ₑ (1)\n• Inside a stable nucleus, the neutron is bound by the strong force (1)\n• Decay would require energy that is not available due to the binding energy of the nucleus (1)' },
      { q: 'Write the equation for beta-minus (β⁻) decay in terms of quarks.', marks: 2, markScheme: '• d → u + e⁻ + ν̄ₑ (1)\n• A down quark changes to an up quark via the weak interaction / W⁻ boson (1)' },
      { q: 'Write the equation for beta-plus (β⁺) decay in terms of quarks.', marks: 2, markScheme: '• u → d + e⁺ + νₑ (1)\n• An up quark changes to a down quark via the weak interaction / W⁺ boson (1)' },
      { q: 'State what is meant by the photoelectric effect.', marks: 2, markScheme: '• The emission of electrons from a metal surface (1)\n• When electromagnetic radiation of sufficiently high frequency is incident on it (1)' },
      { q: 'State Einstein\'s photoelectric equation and define each term.', marks: 3, markScheme: '• hf = φ + Eₖ(max) (1)\n• φ is the work function, the minimum energy needed to release an electron from the surface (1)\n• Eₖ(max) is the maximum kinetic energy of the emitted photoelectron (1)' },
      { q: 'The work function of sodium is 2.3 eV. Calculate the threshold frequency. (h = 6.63 × 10⁻³⁴ J s, 1 eV = 1.60 × 10⁻¹⁹ J)', marks: 2, markScheme: '• φ = hf₀, so f₀ = φ/h = (2.3 × 1.60 × 10⁻¹⁹) / (6.63 × 10⁻³⁴) (1)\n• f₀ = 5.6 × 10¹⁴ Hz (1)' },
      { q: 'Explain why increasing the intensity of light below the threshold frequency does not cause photoelectric emission.', marks: 3, markScheme: '• Each photon has energy hf which is less than the work function (1)\n• Increasing intensity increases the number of photons, not their individual energy (1)\n• A single photon interacts with a single electron, so no electron can gain enough energy to escape (1)' },
      { q: 'Calculate the energy of a photon of wavelength 450 nm. (h = 6.63 × 10⁻³⁴ J s, c = 3.00 × 10⁸ m s⁻¹)', marks: 2, markScheme: '• E = hc/λ = (6.63 × 10⁻³⁴ × 3.00 × 10⁸) / (450 × 10⁻⁹) (1)\n• E = 4.42 × 10⁻¹⁹ J (or 2.76 eV) (1)' },
      { q: 'Explain what is meant by the wave-particle duality of electrons.', marks: 2, markScheme: '• Electrons can behave as particles (e.g. in collisions, photoelectric effect) (1)\n• And as waves (e.g. electron diffraction through a thin crystal) (1)' },
      { q: 'Calculate the de Broglie wavelength of an electron travelling at 2.0 × 10⁶ m s⁻¹. (h = 6.63 × 10⁻³⁴ J s, mₑ = 9.11 × 10⁻³¹ kg)', marks: 2, markScheme: '• λ = h / mv = 6.63 × 10⁻³⁴ / (9.11 × 10⁻³¹ × 2.0 × 10⁶) (1)\n• λ = 3.6 × 10⁻¹⁰ m (0.36 nm) (1)' },
      { q: 'Describe the line spectrum of hydrogen and explain how it provides evidence for discrete energy levels in atoms.', marks: 3, markScheme: '• Hydrogen emits light at specific discrete wavelengths/frequencies only (1)\n• Photon emitted when electron transitions from higher to lower energy level (1)\n• hf = E₂ − E₁, discrete frequencies imply discrete energy levels (1)' },
      { q: 'An electron in a hydrogen atom drops from the n = 3 level (−1.51 eV) to the n = 2 level (−3.40 eV). Calculate the wavelength of the emitted photon. (h = 6.63 × 10⁻³⁴ J s, c = 3.00 × 10⁸ m s⁻¹, 1 eV = 1.60 × 10⁻¹⁹ J)', marks: 3, markScheme: '• ΔE = (−1.51) − (−3.40) = 1.89 eV = 1.89 × 1.60 × 10⁻¹⁹ = 3.02 × 10⁻¹⁹ J (1)\n• λ = hc / ΔE = (6.63 × 10⁻³⁴ × 3.00 × 10⁸) / (3.02 × 10⁻¹⁹) (1)\n• λ = 6.59 × 10⁻⁷ m ≈ 659 nm (red light) (1)' },
      { q: 'State three quantities that are conserved in all particle interactions.', marks: 2, markScheme: '• Charge, baryon number, lepton number (1)\n• Also: energy/momentum (any three for 1 mark, all key ones for 2 marks) (1)' },
      { q: 'A pion (π⁺) has quark composition ud̄. Explain why it is classified as a meson.', marks: 2, markScheme: '• A meson consists of a quark-antiquark pair (1)\n• π⁺ = u + d̄ which is one quark and one antiquark (1)' },
      { q: 'State the difference between a hadron and a lepton.', marks: 2, markScheme: '• Hadrons are made of quarks and experience the strong force (1)\n• Leptons are fundamental particles and do not experience the strong force (1)' },
      { q: 'A kaon (K⁺) decays into a muon (μ⁺) and a neutrino. Write the decay equation and state which force is responsible.', marks: 2, markScheme: '• K⁺ → μ⁺ + νμ (1)\n• Weak nuclear force (because strangeness is not conserved) (1)' },
      { q: 'Explain the concept of strangeness and state when it is conserved.', marks: 3, markScheme: '• Strangeness is a quantum number assigned to particles containing strange quarks (1)\n• Strange quark has strangeness = −1, anti-strange quark has strangeness = +1 (1)\n• Strangeness is conserved in strong and electromagnetic interactions but not in weak interactions (1)' },
      { q: 'Electrons are accelerated through a potential difference of 5000 V. Calculate their kinetic energy in joules and their de Broglie wavelength. (e = 1.60 × 10⁻¹⁹ C, h = 6.63 × 10⁻³⁴ J s, mₑ = 9.11 × 10⁻³¹ kg)', marks: 4, markScheme: '• Eₖ = eV = 1.60 × 10⁻¹⁹ × 5000 = 8.0 × 10⁻¹⁶ J (1)\n• Eₖ = ½mv², so v = √(2Eₖ/m) = √(2 × 8.0 × 10⁻¹⁶ / 9.11 × 10⁻³¹) = 4.19 × 10⁷ m s⁻¹ (1)\n• λ = h / mv = 6.63 × 10⁻³⁴ / (9.11 × 10⁻³¹ × 4.19 × 10⁷) (1)\n• λ = 1.74 × 10⁻¹¹ m (0.017 nm) (1)' },
      { q: 'State three observations of the photoelectric effect that cannot be explained by the wave theory of light.', marks: 3, markScheme: '• No emission below the threshold frequency regardless of intensity (1)\n• Emission is instantaneous with no time delay (1)\n• Maximum kinetic energy of photoelectrons depends on frequency, not intensity (1)' },
      { q: 'Explain why the strong nuclear force must be repulsive at very short separations (less than about 0.5 fm).', marks: 2, markScheme: '• If it were only attractive, nucleons would collapse into a point (1)\n• The repulsive core at very short range prevents nucleons from overlapping and keeps the nucleus stable (1)' },
      { q: 'State the range of the strong nuclear force and describe how it varies with nucleon separation.', marks: 3, markScheme: '• Range is approximately 3–4 fm (1)\n• Attractive between about 0.5 fm and 3 fm, with maximum attraction around 1 fm (1)\n• Repulsive below about 0.5 fm (1)' },
      { q: 'In electron capture, a proton in a nucleus absorbs an inner orbital electron. Write the quark equation and state the particle emitted.', marks: 3, markScheme: '• p + e⁻ → n + νₑ (1)\n• In terms of quarks: u + e⁻ → d + νₑ (1)\n• An electron neutrino is emitted / mediated by W⁺ boson (1)' },
      { q: 'A photon of energy 3.5 eV is incident on a metal surface with work function 1.8 eV. Calculate the maximum kinetic energy of the emitted photoelectrons in eV and in joules.', marks: 3, markScheme: '• Eₖ(max) = hf − φ = 3.5 − 1.8 = 1.7 eV (1)\n• In joules: 1.7 × 1.60 × 10⁻¹⁹ = 2.72 × 10⁻¹⁹ J (1)\n• Unit conversion shown correctly (1)' },
      { q: 'Explain why the existence of the neutrino was proposed during studies of beta decay.', marks: 3, markScheme: '• In beta decay, the emitted electrons have a continuous range of kinetic energies (1)\n• This would violate conservation of energy and momentum if only two particles were produced (1)\n• A neutrino was proposed to carry away the missing energy and momentum (1)' },
      { q: 'State two differences between baryons and mesons.', marks: 2, markScheme: '• Baryons are made of three quarks; mesons are made of a quark-antiquark pair (1)\n• Baryons have baryon number +1 (or −1 for antibaryons); mesons have baryon number 0 (1)' },
      { q: 'The ground state energy of hydrogen is −13.6 eV. Calculate the ionisation energy in joules.', marks: 2, markScheme: '• Ionisation energy = 13.6 eV (energy needed to remove electron from ground state to infinity where E = 0) (1)\n• = 13.6 × 1.60 × 10⁻¹⁹ = 2.18 × 10⁻¹⁸ J (1)' },
      { q: 'State what is meant by the term "virtual photon" in the context of electromagnetic interactions.', marks: 2, markScheme: '• A photon that is exchanged between charged particles to mediate the electromagnetic force (1)\n• It cannot be directly detected / exists for a very short time consistent with the uncertainty principle (1)' },
      { q: 'Determine whether the following interaction conserves baryon number, lepton number, and charge: p + p → p + p + π⁰.', marks: 3, markScheme: '• Baryon number: LHS = 1+1 = 2, RHS = 1+1+0 = 2 ✓ (1)\n• Lepton number: LHS = 0, RHS = 0 ✓ (1)\n• Charge: LHS = +1+1 = +2, RHS = +1+1+0 = +2 ✓ All conserved, interaction is allowed (1)' },
      { q: 'Explain the significance of the stopping potential in a photoelectric experiment.', marks: 3, markScheme: '• The stopping potential Vₛ is the minimum PD needed to stop the most energetic photoelectrons (1)\n• eVₛ = Eₖ(max) = hf − φ (1)\n• A graph of Vₛ against f gives a straight line with gradient h/e and y-intercept −φ/e (1)' },
      { q: 'An electron is confined to a region of width 1.0 × 10⁻¹⁰ m. Estimate its minimum momentum using the de Broglie relation. (h = 6.63 × 10⁻³⁴ J s)', marks: 2, markScheme: '• λ ≈ 2 × width = 2.0 × 10⁻¹⁰ m (standing wave condition) (1)\n• p = h/λ = 6.63 × 10⁻³⁴ / 2.0 × 10⁻¹⁰ = 3.3 × 10⁻²⁴ kg m s⁻¹ (1)' },
      { q: 'State the classification (baryon, meson, or lepton) of each: proton, electron, pion, neutron, muon.', marks: 2, markScheme: '• Baryons: proton, neutron; Mesons: pion (1)\n• Leptons: electron, muon (1)' },
      { q: 'Explain why photons of visible light can cause the photoelectric effect in caesium (φ = 2.1 eV) but not in platinum (φ = 6.4 eV).', marks: 3, markScheme: '• Visible photons have energies approximately 1.8 to 3.1 eV (1)\n• For caesium, photon energy > work function so electrons can be emitted (1)\n• For platinum, photon energy < work function so no emission occurs (1)' },
      { q: 'Describe how electron diffraction provides evidence for the wave nature of particles.', marks: 3, markScheme: '• Electrons are fired at a thin polycrystalline graphite target (1)\n• A pattern of concentric rings is observed on a fluorescent screen (1)\n• This diffraction pattern is characteristic of wave behaviour, with ring spacing related to the de Broglie wavelength (1)' },
      { q: 'A Σ⁺ particle (quark composition uus) decays into a proton and a π⁰. Verify that charge and baryon number are conserved.', marks: 3, markScheme: '• Charge: Σ⁺ = +⅔+⅔−⅓ = +1; proton = +1, π⁰ = 0; LHS = +1, RHS = +1 ✓ (1)\n• Baryon number: Σ⁺ = ⅓+⅓+⅓ = 1; proton = 1, π⁰ = 0; LHS = 1, RHS = 1 ✓ (1)\n• Strangeness: Σ⁺ has S = −1, products have S = 0, so strangeness is not conserved → weak interaction (1)' }
    ]
  },
  '3.3': {
    name: 'Waves',
    questions: [
      { q: 'Define the term "wavelength".', marks: 1, markScheme: '• The minimum distance between two points oscillating in phase / distance between successive crests (1)' },
      { q: 'Define the term "frequency".', marks: 1, markScheme: '• The number of complete oscillations per unit time / per second (1)' },
      { q: 'State the wave equation relating wave speed, frequency, and wavelength.', marks: 1, markScheme: '• v = fλ (1)' },
      { q: 'Define the term "amplitude" of a wave.', marks: 1, markScheme: '• The maximum displacement from the equilibrium position (1)' },
      { q: 'Distinguish between a transverse and a longitudinal wave. Give one example of each.', marks: 3, markScheme: '• Transverse: oscillations are perpendicular to the direction of energy transfer (1)\n• Longitudinal: oscillations are parallel to the direction of energy transfer (1)\n• Examples: transverse — light/EM waves; longitudinal — sound waves (1)' },
      { q: 'State what is meant by a "progressive wave".', marks: 1, markScheme: '• A wave that transfers energy from one place to another (1)' },
      { q: 'Explain what is meant by the phase difference between two points on a wave.', marks: 2, markScheme: '• The fraction of a cycle by which one point leads or lags behind another (1)\n• Measured in radians (or degrees), e.g. points one wavelength apart have phase difference 2π (1)' },
      { q: 'State the conditions required for the formation of a stationary wave.', marks: 2, markScheme: '• Two waves of the same frequency/wavelength and similar amplitude (1)\n• Travelling in opposite directions and superposing (1)' },
      { q: 'Describe the differences between a stationary wave and a progressive wave.', marks: 4, markScheme: '• Stationary: no net energy transfer; progressive: energy is transferred (1)\n• Stationary: nodes and antinodes; progressive: all points have same amplitude (1)\n• Stationary: points between adjacent nodes oscillate in phase; progressive: phase varies continuously along the wave (1)\n• Stationary: amplitude varies from zero (node) to maximum (antinode); progressive: all points have the same amplitude (1)' },
      { q: 'A string of length 1.2 m vibrates in its third harmonic. Calculate the wavelength.', marks: 2, markScheme: '• Third harmonic: L = 3λ/2 (1)\n• λ = 2L/3 = 2 × 1.2 / 3 = 0.80 m (1)' },
      { q: 'State the principle of superposition.', marks: 2, markScheme: '• When two or more waves meet at a point (1)\n• The resultant displacement is the vector sum of the individual displacements (1)' },
      { q: 'Define constructive interference and state the condition for it to occur.', marks: 2, markScheme: '• Constructive interference: superposition produces a resultant with larger amplitude (1)\n• Occurs when the path difference is a whole number of wavelengths (nλ) / phase difference is 0 or 2nπ (1)' },
      { q: 'Define destructive interference and state the condition for it to occur.', marks: 2, markScheme: '• Destructive interference: superposition produces a resultant with smaller or zero amplitude (1)\n• Occurs when the path difference is (n+½)λ / phase difference is (2n+1)π (1)' },
      { q: 'State what is meant by coherent sources.', marks: 2, markScheme: '• Sources that emit waves with a constant phase difference (1)\n• And the same frequency (1)' },
      { q: 'Describe Young\'s double slit experiment and explain how it demonstrates the wave nature of light.', marks: 4, markScheme: '• Monochromatic light passes through a single slit then through two narrow slits (1)\n• An interference pattern of bright and dark fringes is observed on a screen (1)\n• Bright fringes occur where path difference = nλ (constructive interference) (1)\n• This pattern can only be explained by superposition of waves, not particles (1)' },
      { q: 'In a Young\'s double slit experiment, the slit separation is 0.50 mm, the screen distance is 1.5 m, and the fringe spacing is 1.8 mm. Calculate the wavelength of light used.', marks: 2, markScheme: '• w = λD/s, so λ = ws/D = (1.8 × 10⁻³ × 0.50 × 10⁻³) / 1.5 (1)\n• λ = 6.0 × 10⁻⁷ m = 600 nm (1)' },
      { q: 'State the equation for the diffraction grating and define each term.', marks: 2, markScheme: '• d sin θ = nλ (1)\n• d = slit spacing, θ = angle of diffraction, n = order number, λ = wavelength (1)' },
      { q: 'A diffraction grating has 600 lines per mm. Calculate the slit spacing.', marks: 1, markScheme: '• d = 1 / (600 × 10³) = 1.67 × 10⁻⁶ m (1)' },
      { q: 'A diffraction grating with 500 lines per mm is used with light of wavelength 550 nm. Calculate the maximum order of diffraction visible.', marks: 3, markScheme: '• d = 1/(500 × 10³) = 2.0 × 10⁻⁶ m (1)\n• At maximum order, sin θ = 1, so n = d/λ = 2.0 × 10⁻⁶ / 550 × 10⁻⁹ = 3.64 (1)\n• Maximum order n = 3 (must be a whole number) (1)' },
      { q: 'Explain why a diffraction grating produces sharper maxima than a double slit.', marks: 2, markScheme: '• A grating has many more slits, so many more waves superpose (1)\n• Constructive interference occurs over a very narrow range of angles, giving sharper, brighter maxima (1)' },
      { q: 'State what is meant by polarisation of a wave.', marks: 2, markScheme: '• Polarisation is the restriction of oscillations to a single plane (1)\n• Only transverse waves can be polarised (1)' },
      { q: 'Explain how Polaroid filters can be used to demonstrate that light is a transverse wave.', marks: 3, markScheme: '• Pass unpolarised light through a Polaroid filter to polarise it (1)\n• Place a second Polaroid (analyser) and rotate it (1)\n• The transmitted intensity varies from maximum to zero, proving oscillations are in one plane / transverse (1)' },
      { q: 'State Snell\'s law of refraction.', marks: 1, markScheme: '• n₁ sin θ₁ = n₂ sin θ₂ (1)' },
      { q: 'Define the refractive index of a material.', marks: 1, markScheme: '• n = c / v, where c is the speed of light in vacuum and v is the speed of light in the material (1)' },
      { q: 'Explain what is meant by total internal reflection and state the two conditions required for it to occur.', marks: 3, markScheme: '• Total internal reflection: all light is reflected back into the denser medium at a boundary (1)\n• Light must be travelling from a denser to a less dense medium (higher to lower refractive index) (1)\n• The angle of incidence must be greater than the critical angle (1)' },
      { q: 'Calculate the critical angle for glass of refractive index 1.50 at a glass-air boundary.', marks: 2, markScheme: '• sin C = n₂/n₁ = 1/1.50 (1)\n• C = sin⁻¹(0.667) = 41.8° (1)' },
      { q: 'A sound wave has a frequency of 440 Hz and travels at 340 m s⁻¹ in air. Calculate its wavelength.', marks: 1, markScheme: '• λ = v/f = 340/440 = 0.773 m (1)' },
      { q: 'Explain the term "path difference" and state its relationship to the type of interference observed.', marks: 3, markScheme: '• Path difference is the difference in distance travelled by two waves from their sources to a given point (1)\n• If path difference = nλ, constructive interference occurs (1)\n• If path difference = (n+½)λ, destructive interference occurs (1)' },
      { q: 'A stationary wave is formed on a string fixed at both ends. The string vibrates at its fundamental frequency of 250 Hz. The length of the string is 0.60 m. Calculate the speed of the wave on the string.', marks: 2, markScheme: '• Fundamental: L = λ/2, so λ = 2L = 1.20 m (1)\n• v = fλ = 250 × 1.20 = 300 m s⁻¹ (1)' },
      { q: 'Describe how you would demonstrate stationary waves using microwaves and a metal reflector.', marks: 3, markScheme: '• Direct microwaves at a metal reflector so the incident and reflected waves superpose (1)\n• Move a detector probe between the source and reflector (1)\n• Alternating positions of maximum and minimum signal are detected, corresponding to antinodes and nodes (1)' },
      { q: 'Explain why diffraction effects are more significant when the gap width is similar to the wavelength.', marks: 2, markScheme: '• Diffraction is the spreading of waves as they pass through a gap or around an obstacle (1)\n• Maximum spreading occurs when the gap width is approximately equal to the wavelength (1)' },
      { q: 'Light of wavelength 600 nm passes through a single slit of width 0.10 mm. A screen is placed 2.0 m from the slit. Calculate the width of the central maximum.', marks: 3, markScheme: '• For single slit: sin θ ≈ θ = λ/a for first minimum (1)\n• θ = 600 × 10⁻⁹ / 0.10 × 10⁻³ = 6.0 × 10⁻³ rad (1)\n• Width of central max = 2 × θ × D = 2 × 6.0 × 10⁻³ × 2.0 = 0.024 m = 24 mm (1)' },
      { q: 'State what happens to the speed, wavelength, and frequency of light when it passes from air into glass.', marks: 2, markScheme: '• Speed decreases, wavelength decreases (1)\n• Frequency stays the same (1)' },
      { q: 'An optical fibre uses total internal reflection to transmit light. Explain one advantage of using a cladding layer around the core of the fibre.', marks: 2, markScheme: '• Cladding has a lower refractive index than the core, ensuring total internal reflection occurs (1)\n• Prevents signal loss / cross-talk between adjacent fibres / protects the core surface (1)' },
      { q: 'A pipe open at both ends has a length of 0.85 m. Calculate the frequency of the fundamental standing wave in the pipe. (Speed of sound = 340 m s⁻¹)', marks: 2, markScheme: '• Open both ends: L = λ/2, so λ = 2 × 0.85 = 1.70 m (1)\n• f = v/λ = 340 / 1.70 = 200 Hz (1)' },
      { q: 'A pipe closed at one end has a length of 0.85 m. Calculate the frequency of the fundamental standing wave. (Speed of sound = 340 m s⁻¹)', marks: 2, markScheme: '• Closed one end: L = λ/4, so λ = 4 × 0.85 = 3.40 m (1)\n• f = v/λ = 340 / 3.40 = 100 Hz (1)' },
      { q: 'A diffraction grating produces a second-order maximum at an angle of 30° for light of wavelength 500 nm. Calculate the number of lines per mm on the grating.', marks: 3, markScheme: '• d sin θ = nλ, so d = nλ / sin θ = 2 × 500 × 10⁻⁹ / sin 30° (1)\n• d = 2.0 × 10⁻⁶ m (1)\n• Lines per mm = 1 / (2.0 × 10⁻⁶ × 10³) = 500 lines per mm (1)' },
      { q: 'Explain why white light produces a spectrum when passed through a diffraction grating, but a laser produces dots.', marks: 3, markScheme: '• White light contains a range of wavelengths (1)\n• d sin θ = nλ, so different wavelengths diffract at different angles, forming a spectrum (1)\n• A laser is monochromatic so produces sharp dots/maxima at specific angles (1)' },
      { q: 'State two properties of a laser beam that make it useful for experiments involving diffraction and interference.', marks: 2, markScheme: '• Monochromatic (single wavelength/frequency) (1)\n• Coherent (constant phase relationship) (1)' },
      { q: 'Describe how you would use a resonance tube experiment to measure the speed of sound in air.', marks: 4, markScheme: '• Place a tuning fork of known frequency above an open tube partially submerged in water (1)\n• Lower the tube until the first loud resonance is heard; measure length L₁ (1)\n• Continue lowering until the second resonance; measure length L₂ (1)\n• Speed of sound v = 2f(L₂ − L₁), where f is the frequency of the tuning fork (1)' },
      { q: 'Calculate the intensity of a wave if the power transmitted is 0.50 W through an area of 2.0 m².', marks: 1, markScheme: '• I = P/A = 0.50 / 2.0 = 0.25 W m⁻² (1)' },
      { q: 'State the relationship between the intensity of a wave and its amplitude.', marks: 1, markScheme: '• Intensity is proportional to amplitude squared: I ∝ A² (1)' },
      { q: 'In a double slit experiment, the intensity at the centre of the pattern is I₀. State the intensity at the first dark fringe.', marks: 1, markScheme: '• Zero (0) (1)' },
      { q: 'Two loudspeakers connected to the same signal generator produce sound of wavelength 0.40 m. A listener walks along a line parallel to the speakers, 5.0 m away. The speakers are 1.2 m apart. Calculate the angle to the first minimum from the central maximum.', marks: 3, markScheme: '• First minimum: path difference = λ/2 = 0.20 m (1)\n• sin θ = path difference / d = 0.20 / 1.2 (1)\n• θ = sin⁻¹(0.167) = 9.6° (1)' },
      { q: 'Explain why you can hear sound around a corner but cannot see around a corner.', marks: 3, markScheme: '• Diffraction is significant when the gap/obstacle size is comparable to the wavelength (1)\n• Sound has wavelengths of order metres, comparable to doorways/corners (1)\n• Light has wavelengths of order 10⁻⁷ m, much smaller than everyday obstacles, so negligible diffraction (1)' },
      { q: 'A microwave source of frequency 10 GHz is used in a double slit experiment. Calculate the wavelength of the microwaves. (c = 3.0 × 10⁸ m s⁻¹)', marks: 1, markScheme: '• λ = c/f = 3.0 × 10⁸ / 10 × 10⁹ = 0.030 m = 3.0 cm (1)' },
      { q: 'Describe an experiment to determine the wavelength of a laser using a diffraction grating.', marks: 4, markScheme: '• Set up the laser to shine through a diffraction grating onto a distant screen (1)\n• Measure the distance D from grating to screen and the distance x from central to nth order maximum (1)\n• Calculate θ using tan θ = x/D (1)\n• Use d sin θ = nλ to calculate λ, where d is the known slit spacing (1)' },
      { q: 'State the order of magnitude of the wavelength of visible light.', marks: 1, markScheme: '• 10⁻⁷ m (or ~400–700 nm) (1)' }
    ]
  },
  '3.4': {
    name: 'Mechanics and Materials',
    questions: [
      { q: 'State the difference between a scalar and a vector quantity. Give one example of each.', marks: 2, markScheme: '• Scalar has magnitude only; vector has magnitude and direction (1)\n• Example: scalar — mass/speed/energy; vector — force/velocity/displacement (1)' },
      { q: 'Define displacement.', marks: 1, markScheme: '• The distance moved in a specified direction from a reference point (1)' },
      { q: 'A boat travels 3.0 km north and then 4.0 km east. Calculate the magnitude and direction of its displacement.', marks: 3, markScheme: '• Magnitude = √(3.0² + 4.0²) = √25 = 5.0 km (1)\n• Direction: tan θ = 4.0/3.0, θ = 53° (1)\n• 53° east of north (or bearing 053°) (1)' },
      { q: 'State the four SUVAT equations.', marks: 2, markScheme: '• v = u + at; s = ut + ½at² (1)\n• v² = u² + 2as; s = ½(u + v)t (1)' },
      { q: 'A ball is thrown vertically upwards with an initial speed of 20 m s⁻¹. Calculate the maximum height reached. (g = 9.81 m s⁻²)', marks: 2, markScheme: '• At max height v = 0; v² = u² + 2as → 0 = 20² + 2(−9.81)s (1)\n• s = 400 / 19.62 = 20.4 m (1)' },
      { q: 'A car accelerates uniformly from rest to 30 m s⁻¹ in 8.0 s. Calculate the distance travelled.', marks: 2, markScheme: '• s = ½(u + v)t = ½(0 + 30) × 8.0 (1)\n• s = 120 m (1)' },
      { q: 'State Newton\'s first law of motion.', marks: 1, markScheme: '• An object remains at rest or in uniform motion in a straight line unless acted upon by a resultant force (1)' },
      { q: 'State Newton\'s second law of motion.', marks: 1, markScheme: '• The rate of change of momentum of an object is proportional to the resultant force acting on it and takes place in the direction of that force / F = ma (1)' },
      { q: 'State Newton\'s third law of motion.', marks: 2, markScheme: '• When two objects interact, they exert equal and opposite forces on each other (1)\n• The forces are the same type and act on different objects (1)' },
      { q: 'A 1200 kg car accelerates at 2.5 m s⁻². The driving force is 4000 N. Calculate the resistive force acting on the car.', marks: 2, markScheme: '• F(net) = ma = 1200 × 2.5 = 3000 N (1)\n• Resistive force = 4000 − 3000 = 1000 N (1)' },
      { q: 'Define the moment of a force about a point.', marks: 1, markScheme: '• Moment = force × perpendicular distance from the line of action of the force to the point (1)' },
      { q: 'State the principle of moments.', marks: 2, markScheme: '• For a body in rotational equilibrium (1)\n• The sum of clockwise moments about any point equals the sum of anticlockwise moments (1)' },
      { q: 'A uniform beam of length 4.0 m and weight 200 N is supported at each end. A 500 N load is placed 1.0 m from one end. Calculate the reaction forces at each support.', marks: 3, markScheme: '• Taking moments about one end: R₂ × 4.0 = 500 × 1.0 + 200 × 2.0 (1)\n• R₂ = (500 + 400) / 4.0 = 225 N (1)\n• R₁ = 700 − 225 = 475 N (1)' },
      { q: 'Define linear momentum and state its SI unit.', marks: 1, markScheme: '• p = mv, unit: kg m s⁻¹ (1)' },
      { q: 'State the principle of conservation of momentum.', marks: 2, markScheme: '• The total momentum of a system remains constant (1)\n• Provided no external resultant force acts on the system (1)' },
      { q: 'A 2.0 kg trolley moving at 3.0 m s⁻¹ collides with a stationary 1.0 kg trolley. They stick together. Calculate their common velocity after the collision.', marks: 2, markScheme: '• m₁u₁ = (m₁ + m₂)v → 2.0 × 3.0 = (2.0 + 1.0) × v (1)\n• v = 6.0 / 3.0 = 2.0 m s⁻¹ (1)' },
      { q: 'Show that the collision above is inelastic by calculating the kinetic energy before and after.', marks: 3, markScheme: '• KE before = ½ × 2.0 × 3.0² = 9.0 J (1)\n• KE after = ½ × 3.0 × 2.0² = 6.0 J (1)\n• KE is not conserved (9.0 J ≠ 6.0 J), so the collision is inelastic (1)' },
      { q: 'Define the work done by a force.', marks: 1, markScheme: '• W = Fs cos θ, where θ is the angle between the force and the direction of displacement (1)' },
      { q: 'A force of 50 N pulls a box 8.0 m along a surface at an angle of 30° to the horizontal. Calculate the work done.', marks: 2, markScheme: '• W = Fs cos θ = 50 × 8.0 × cos 30° (1)\n• W = 346 J ≈ 350 J (1)' },
      { q: 'Define power and state its SI unit.', marks: 1, markScheme: '• Power = rate of doing work / rate of energy transfer, P = W/t, unit: watt (W) (1)' },
      { q: 'A car of mass 1500 kg travels at a constant speed of 25 m s⁻¹ against a total resistive force of 800 N. Calculate the power output of the engine.', marks: 2, markScheme: '• At constant speed, driving force = resistive force = 800 N (1)\n• P = Fv = 800 × 25 = 20 000 W = 20 kW (1)' },
      { q: 'State the principle of conservation of energy.', marks: 1, markScheme: '• Energy cannot be created or destroyed, only transferred from one form to another (1)' },
      { q: 'A 0.50 kg ball is dropped from a height of 10 m. Calculate its speed just before hitting the ground. (g = 9.81 m s⁻²)', marks: 2, markScheme: '• mgh = ½mv², so v = √(2gh) = √(2 × 9.81 × 10) (1)\n• v = 14.0 m s⁻¹ (1)' },
      { q: 'Define density and state its SI unit.', marks: 1, markScheme: '• ρ = m/V, unit: kg m⁻³ (1)' },
      { q: 'A metal cube has sides of length 0.050 m and mass 0.35 kg. Calculate its density.', marks: 2, markScheme: '• V = (0.050)³ = 1.25 × 10⁻⁴ m³ (1)\n• ρ = 0.35 / 1.25 × 10⁻⁴ = 2800 kg m⁻³ (1)' },
      { q: 'State Hooke\'s law.', marks: 1, markScheme: '• The extension of a spring is directly proportional to the applied force, up to the limit of proportionality (F = kx) (1)' },
      { q: 'A spring has a spring constant of 40 N m⁻¹. Calculate the energy stored when it is extended by 0.15 m.', marks: 2, markScheme: '• E = ½kx² = ½ × 40 × 0.15² (1)\n• E = 0.45 J (1)' },
      { q: 'Define stress, strain, and Young\'s modulus.', marks: 3, markScheme: '• Stress = force / cross-sectional area (σ = F/A), unit: Pa (1)\n• Strain = extension / original length (ε = ΔL/L), no unit (1)\n• Young\'s modulus = stress / strain (E = σ/ε), unit: Pa (1)' },
      { q: 'A copper wire of length 2.0 m and diameter 0.80 mm is stretched by a force of 100 N. Young\'s modulus for copper is 1.2 × 10¹¹ Pa. Calculate the extension of the wire.', marks: 3, markScheme: '• A = π(d/2)² = π(0.40 × 10⁻³)² = 5.03 × 10⁻⁷ m² (1)\n• E = FL/AΔL, so ΔL = FL/(AE) = (100 × 2.0) / (5.03 × 10⁻⁷ × 1.2 × 10¹¹) (1)\n• ΔL = 3.3 × 10⁻³ m = 3.3 mm (1)' },
      { q: 'Describe the stress-strain graph for a ductile material up to fracture, labelling key points.', marks: 4, markScheme: '• Linear region up to the limit of proportionality where Hooke\'s law is obeyed (1)\n• Elastic limit: beyond this, permanent deformation occurs (1)\n• Yield point: large increase in strain for small increase in stress (1)\n• UTS (ultimate tensile stress): maximum stress before necking, then fracture (1)' },
      { q: 'Distinguish between elastic and plastic deformation.', marks: 2, markScheme: '• Elastic: material returns to original shape when force is removed / no permanent deformation (1)\n• Plastic: material does not return to original shape / permanent deformation occurs (1)' },
      { q: 'A projectile is launched horizontally from a cliff 80 m high at 15 m s⁻¹. Calculate the time to reach the ground and the horizontal distance travelled. (g = 9.81 m s⁻²)', marks: 3, markScheme: '• Vertically: s = ½gt², t = √(2s/g) = √(2 × 80/9.81) = 4.04 s (1)\n• Horizontal distance = v × t = 15 × 4.04 (1)\n• = 60.6 m ≈ 61 m (1)' },
      { q: 'A ball is launched at 25 m s⁻¹ at 40° above the horizontal. Calculate the maximum height reached. (g = 9.81 m s⁻²)', marks: 3, markScheme: '• Vertical component: uᵧ = 25 sin 40° = 16.1 m s⁻¹ (1)\n• At max height vᵧ = 0: v² = u² + 2as → 0 = 16.1² − 2(9.81)s (1)\n• s = 259.2 / 19.62 = 13.2 m (1)' },
      { q: 'Explain what is meant by the centre of gravity of an object.', marks: 1, markScheme: '• The point at which the entire weight of the object may be considered to act (1)' },
      { q: 'A crane lifts a 2000 kg load through a vertical height of 15 m in 30 s. Calculate the useful power output of the crane. (g = 9.81 m s⁻²)', marks: 2, markScheme: '• W = mgh = 2000 × 9.81 × 15 = 294 300 J (1)\n• P = W/t = 294 300 / 30 = 9810 W ≈ 9.8 kW (1)' },
      { q: 'Define impulse and state its relationship to momentum.', marks: 2, markScheme: '• Impulse = force × time (FΔt) (1)\n• Impulse equals the change in momentum: FΔt = Δ(mv) (1)' },
      { q: 'A 0.15 kg cricket ball travelling at 30 m s⁻¹ is hit back in the opposite direction at 40 m s⁻¹. The contact time is 0.002 s. Calculate the average force on the ball.', marks: 3, markScheme: '• Change in momentum = m(v − u) = 0.15 × (40 − (−30)) = 0.15 × 70 = 10.5 kg m s⁻¹ (1)\n• F = Δp/Δt = 10.5 / 0.002 (1)\n• F = 5250 N (1)' },
      { q: 'Explain why a car crumple zone reduces injuries in a collision.', marks: 3, markScheme: '• The crumple zone increases the time of deceleration / collision time (1)\n• For a given change in momentum, a longer time means a smaller force (F = Δp/Δt) (1)\n• Therefore the force on the passengers is reduced, reducing injury (1)' },
      { q: 'Two springs, each with spring constant 20 N m⁻¹, are connected in series. Calculate the effective spring constant.', marks: 2, markScheme: '• In series: 1/k = 1/k₁ + 1/k₂ = 1/20 + 1/20 = 2/20 (1)\n• k = 10 N m⁻¹ (1)' },
      { q: 'Two springs, each with spring constant 20 N m⁻¹, are connected in parallel. Calculate the effective spring constant.', marks: 1, markScheme: '• In parallel: k = k₁ + k₂ = 20 + 20 = 40 N m⁻¹ (1)' },
      { q: 'A rubber band is stretched and released. The loading and unloading force-extension curves do not follow the same path. Explain the significance of this.', marks: 2, markScheme: '• The area between the loading and unloading curves represents energy dissipated as heat (1)\n• This is called hysteresis; the rubber band does not return all the stored elastic energy (1)' },
      { q: 'Define the efficiency of a system.', marks: 1, markScheme: '• Efficiency = useful output energy (or power) / total input energy (or power) × 100% (1)' },
      { q: 'A motor lifts a 50 kg mass through 3.0 m in 5.0 s. The motor uses 500 W of electrical power. Calculate the efficiency. (g = 9.81 m s⁻²)', marks: 3, markScheme: '• Useful work = mgh = 50 × 9.81 × 3.0 = 1471.5 J (1)\n• Total energy input = Pt = 500 × 5.0 = 2500 J (1)\n• Efficiency = 1471.5 / 2500 × 100 = 58.9% (1)' },
      { q: 'Resolve a 10 N force acting at 60° to the horizontal into horizontal and vertical components.', marks: 2, markScheme: '• Horizontal: 10 cos 60° = 5.0 N (1)\n• Vertical: 10 sin 60° = 8.7 N (1)' },
      { q: 'State the conditions for a body to be in static equilibrium.', marks: 2, markScheme: '• The resultant force in any direction is zero (1)\n• The resultant moment about any point is zero (1)' },
      { q: 'Describe an experiment to determine the Young\'s modulus of a wire.', marks: 5, markScheme: '• Use a long thin wire fixed at one end, passing over a pulley with masses hung from it (1)\n• Measure original length with a metre rule and diameter with a micrometer (several positions) (1)\n• Gradually add masses and measure extension using a reference wire and vernier scale (1)\n• Plot stress (F/A) vs strain (ΔL/L) graph (1)\n• Young\'s modulus = gradient of the linear section of the graph (1)' },
      { q: 'A ball of mass 0.20 kg on a string swings from a height of 0.50 m. At the bottom of the swing it hits a stationary ball of mass 0.30 kg. The first ball stops. Calculate the speed of the second ball after the collision. (g = 9.81 m s⁻²)', marks: 4, markScheme: '• Speed of first ball at bottom: v = √(2gh) = √(2 × 9.81 × 0.50) = 3.13 m s⁻¹ (1)\n• Conservation of momentum: 0.20 × 3.13 = 0.30 × v₂ (1)\n• v₂ = 0.626 / 0.30 = 2.09 m s⁻¹ (1)\n• Check: this is an elastic-type calculation since first ball stops (1)' },
      { q: 'Explain what terminal velocity is and how it is reached by a skydiver.', marks: 3, markScheme: '• At first, weight is greater than air resistance so there is a net downward force and the skydiver accelerates (1)\n• As speed increases, air resistance increases until it equals the weight (1)\n• The resultant force is zero and the skydiver travels at constant (terminal) velocity (1)' },
      { q: 'A wire of original length 3.0 m stretches by 1.5 mm when a stress of 150 MPa is applied. Calculate the Young\'s modulus of the wire.', marks: 2, markScheme: '• Strain = 1.5 × 10⁻³ / 3.0 = 5.0 × 10⁻⁴ (1)\n• E = stress/strain = 150 × 10⁶ / 5.0 × 10⁻⁴ = 3.0 × 10¹¹ Pa (1)' },
      { q: 'Explain what is meant by the breaking stress of a material.', marks: 1, markScheme: '• The maximum stress a material can withstand before it fractures (1)' }
    ]
  },
  '3.5': {
    name: 'Electricity',
    questions: [
      { q: 'Define electric current.', marks: 1, markScheme: '• The rate of flow of charge: I = Q/t (1)' },
      { q: 'Define potential difference.', marks: 1, markScheme: '• The energy transferred per unit charge between two points: V = W/Q (1)' },
      { q: 'Define resistance and state its SI unit.', marks: 1, markScheme: '• R = V/I, unit: ohm (Ω) (1)' },
      { q: 'State Ohm\'s law.', marks: 1, markScheme: '• The current through a conductor is proportional to the potential difference across it, provided the temperature remains constant (1)' },
      { q: 'A current of 2.5 A flows through a component for 3 minutes. Calculate the total charge that flows.', marks: 2, markScheme: '• Q = It = 2.5 × (3 × 60) = 2.5 × 180 (1)\n• Q = 450 C (1)' },
      { q: 'Calculate the resistance of a wire if a PD of 12 V causes a current of 0.40 A to flow.', marks: 1, markScheme: '• R = V/I = 12 / 0.40 = 30 Ω (1)' },
      { q: 'Define resistivity and state its SI unit.', marks: 2, markScheme: '• ρ = RA/L, where R is resistance, A is cross-sectional area, L is length (1)\n• Unit: Ω m (ohm metre) (1)' },
      { q: 'A copper wire has a length of 5.0 m, diameter 0.50 mm, and resistivity 1.7 × 10⁻⁸ Ω m. Calculate its resistance.', marks: 3, markScheme: '• A = π(d/2)² = π(0.25 × 10⁻³)² = 1.96 × 10⁻⁷ m² (1)\n• R = ρL/A = (1.7 × 10⁻⁸ × 5.0) / (1.96 × 10⁻⁷) (1)\n• R = 0.43 Ω (1)' },
      { q: 'Sketch the I-V characteristic for a filament lamp and explain its shape.', marks: 3, markScheme: '• Curve through origin, gradient decreasing as V increases (1)\n• As current increases, the filament gets hotter (1)\n• Resistance increases with temperature, so current increases less rapidly (1)' },
      { q: 'Sketch the I-V characteristic for a diode and explain its key features.', marks: 3, markScheme: '• No current for reverse bias and small forward bias (1)\n• Above the threshold voltage (~0.6 V for silicon), current increases rapidly (1)\n• Very high resistance in reverse bias, very low resistance above threshold in forward bias (1)' },
      { q: 'Sketch the I-V characteristic for an ohmic resistor at constant temperature.', marks: 1, markScheme: '• Straight line through the origin with constant gradient (1)' },
      { q: 'Describe how the resistance of a thermistor (NTC) changes with temperature and state one application.', marks: 2, markScheme: '• Resistance decreases as temperature increases (1)\n• Application: temperature sensor / thermostat / thermometer circuit (1)' },
      { q: 'Describe how the resistance of an LDR changes with light intensity and state one application.', marks: 2, markScheme: '• Resistance decreases as light intensity increases (1)\n• Application: automatic lighting / light meter / burglar alarm (1)' },
      { q: 'Three resistors of 2 Ω, 3 Ω, and 6 Ω are connected in parallel. Calculate the total resistance.', marks: 2, markScheme: '• 1/R = 1/2 + 1/3 + 1/6 = 3/6 + 2/6 + 1/6 = 6/6 = 1 (1)\n• R = 1.0 Ω (1)' },
      { q: 'Three resistors of 4 Ω, 6 Ω, and 10 Ω are connected in series. Calculate the total resistance.', marks: 1, markScheme: '• R = 4 + 6 + 10 = 20 Ω (1)' },
      { q: 'State Kirchhoff\'s first law and the conservation principle it is based on.', marks: 2, markScheme: '• The sum of currents entering a junction equals the sum of currents leaving it (1)\n• Based on conservation of charge (1)' },
      { q: 'State Kirchhoff\'s second law and the conservation principle it is based on.', marks: 2, markScheme: '• The sum of EMFs around a closed loop equals the sum of the PDs around that loop (1)\n• Based on conservation of energy (1)' },
      { q: 'Define electromotive force (EMF) of a cell.', marks: 1, markScheme: '• The energy transferred per unit charge by the cell / the total PD across the cell when no current flows (1)' },
      { q: 'A cell has an EMF of 1.5 V and internal resistance 0.50 Ω. It is connected to an external resistance of 4.5 Ω. Calculate the current and the terminal PD.', marks: 3, markScheme: '• I = ε / (R + r) = 1.5 / (4.5 + 0.50) = 0.30 A (1)\n• Terminal PD = ε − Ir = 1.5 − 0.30 × 0.50 = 1.35 V (1)\n• Or: V = IR = 0.30 × 4.5 = 1.35 V (1)' },
      { q: 'Explain why the terminal PD of a cell is less than its EMF when a current flows.', marks: 2, markScheme: '• When current flows, there is a PD dropped across the internal resistance (lost volts = Ir) (1)\n• Terminal PD = ε − Ir, which is less than ε (1)' },
      { q: 'Describe an experiment to determine the EMF and internal resistance of a cell.', marks: 4, markScheme: '• Connect cell in series with a variable resistor and ammeter; voltmeter across the cell (1)\n• Vary the resistance and record corresponding values of I and V (1)\n• Plot V against I: this gives a straight line (1)\n• y-intercept = EMF (ε), gradient = −r (internal resistance) (1)' },
      { q: 'Calculate the power dissipated in a 12 Ω resistor when a current of 0.50 A flows through it.', marks: 1, markScheme: '• P = I²R = 0.50² × 12 = 3.0 W (1)' },
      { q: 'Calculate the energy transferred in 5 minutes by a 60 W light bulb.', marks: 2, markScheme: '• E = Pt = 60 × (5 × 60) = 60 × 300 (1)\n• E = 18 000 J = 18 kJ (1)' },
      { q: 'Explain the function of a potential divider circuit.', marks: 2, markScheme: '• A potential divider splits the supply voltage into two parts using two resistors in series (1)\n• The output voltage is V_out = (R₂/(R₁+R₂)) × V_in (1)' },
      { q: 'In a potential divider, R₁ = 3 kΩ and R₂ = 7 kΩ, connected to a 10 V supply. Calculate the output voltage across R₂.', marks: 2, markScheme: '• V_out = R₂/(R₁+R₂) × V_in = 7/(3+7) × 10 (1)\n• V_out = 7.0 V (1)' },
      { q: 'Explain how a potential divider with a thermistor can be used to monitor temperature changes.', marks: 3, markScheme: '• Thermistor is placed in series with a fixed resistor across a supply (1)\n• As temperature rises, thermistor resistance decreases (1)\n• The PD across the thermistor decreases (and PD across the fixed resistor increases), which can trigger a circuit (1)' },
      { q: 'Two cells each of EMF 1.5 V and internal resistance 0.5 Ω are connected in series. Calculate the total EMF and total internal resistance.', marks: 2, markScheme: '• Total EMF = 1.5 + 1.5 = 3.0 V (1)\n• Total internal resistance = 0.5 + 0.5 = 1.0 Ω (1)' },
      { q: 'Two identical cells each of EMF 1.5 V and internal resistance 0.5 Ω are connected in parallel. State the total EMF and calculate the total internal resistance.', marks: 2, markScheme: '• Total EMF = 1.5 V (same as one cell) (1)\n• Total internal resistance = 0.5/2 = 0.25 Ω (1)' },
      { q: 'A wire of resistance 10 Ω carries a current of 3.0 A. Calculate the number of electrons passing a point in the wire per second. (e = 1.60 × 10⁻¹⁹ C)', marks: 2, markScheme: '• Q = It = 3.0 × 1 = 3.0 C per second (1)\n• Number of electrons = Q/e = 3.0 / 1.60 × 10⁻¹⁹ = 1.88 × 10¹⁹ (1)' },
      { q: 'Explain what is meant by the drift velocity of charge carriers.', marks: 2, markScheme: '• The average velocity of charge carriers (electrons) along the conductor in the direction of current flow (1)\n• Related to current by I = nAve, where n is number density, A is area, v is drift velocity, e is charge (1)' },
      { q: 'A copper wire of cross-sectional area 2.0 × 10⁻⁶ m² carries a current of 5.0 A. The number density of free electrons in copper is 8.5 × 10²⁸ m⁻³. Calculate the drift velocity. (e = 1.60 × 10⁻¹⁹ C)', marks: 2, markScheme: '• v = I/(nAe) = 5.0 / (8.5 × 10²⁸ × 2.0 × 10⁻⁶ × 1.60 × 10⁻¹⁹) (1)\n• v = 1.84 × 10⁻⁴ m s⁻¹ ≈ 0.18 mm s⁻¹ (1)' },
      { q: 'Explain why a thinner wire has a greater resistance than a thicker wire of the same material and length.', marks: 2, markScheme: '• R = ρL/A; a thinner wire has a smaller cross-sectional area A (1)\n• Since R is inversely proportional to A, smaller A gives larger R (1)' },
      { q: 'A 12 V battery with internal resistance 0.80 Ω is connected to two 6.0 Ω resistors in parallel. Calculate the current drawn from the battery.', marks: 3, markScheme: '• Parallel resistance = (6.0 × 6.0)/(6.0 + 6.0) = 3.0 Ω (1)\n• Total resistance = 3.0 + 0.80 = 3.8 Ω (1)\n• I = 12 / 3.8 = 3.16 A ≈ 3.2 A (1)' },
      { q: 'Calculate the total energy delivered by a 9.0 V battery that supplies a current of 0.20 A for 1 hour.', marks: 2, markScheme: '• E = VIt = 9.0 × 0.20 × 3600 (1)\n• E = 6480 J ≈ 6.5 kJ (1)' },
      { q: 'Explain why a superconductor has zero resistivity below its critical temperature and state one application.', marks: 3, markScheme: '• Below the critical temperature, the resistance of the material drops to zero (1)\n• Charge carriers can flow without energy loss (1)\n• Application: strong electromagnets (MRI scanners), power transmission without loss, maglev trains (1)' },
      { q: 'A 6.0 V supply is connected to a potential divider consisting of a 1.0 kΩ resistor and an LDR. In darkness, the LDR has resistance 9.0 kΩ. In bright light, it has resistance 0.50 kΩ. Calculate the voltage across the LDR in each case.', marks: 4, markScheme: '• In darkness: V = R_LDR/(R_LDR + R) × V_in = 9.0/(9.0+1.0) × 6.0 (1)\n• = 5.4 V (1)\n• In bright light: V = 0.50/(0.50+1.0) × 6.0 (1)\n• = 2.0 V (1)' },
      { q: 'Describe an experiment to investigate the I-V characteristic of a filament lamp.', marks: 4, markScheme: '• Connect lamp in series with variable resistor and ammeter, voltmeter in parallel with lamp (1)\n• Vary the variable resistor to change the current (1)\n• Record pairs of I and V values; reverse the connections for negative values (1)\n• Plot I against V to obtain the characteristic curve (1)' },
      { q: 'Explain, using the concept of electron drift, why a metal wire gets warm when current flows through it.', marks: 3, markScheme: '• Free electrons are accelerated by the electric field and gain kinetic energy (1)\n• They collide with the positive metal ions in the lattice (1)\n• Kinetic energy is transferred to the ions, increasing their vibrational energy and the temperature of the wire (1)' },
      { q: 'A battery of EMF 6.0 V and internal resistance 0.40 Ω is connected to a 2.6 Ω external resistor. Calculate the power dissipated in the internal resistance and in the external resistance.', marks: 3, markScheme: '• I = ε/(R+r) = 6.0/(2.6+0.40) = 2.0 A (1)\n• Power in r = I²r = 2.0² × 0.40 = 1.6 W (1)\n• Power in R = I²R = 2.0² × 2.6 = 10.4 W (1)' },
      { q: 'Show that maximum power is delivered to an external resistance when R = r (impedance matching).', marks: 4, markScheme: '• P = I²R = [ε/(R+r)]² × R = ε²R/(R+r)² (1)\n• To find maximum, differentiate: dP/dR = ε²[(R+r)² − 2R(R+r)] / (R+r)⁴ (1)\n• Setting numerator to zero: (R+r) − 2R = 0, so r = R (1)\n• Therefore maximum power transfer occurs when external resistance equals internal resistance (1)' },
      { q: 'Explain why the resistance of a metal increases with temperature, but the resistance of a semiconductor decreases.', marks: 4, markScheme: '• In a metal: increasing temperature increases lattice vibrations (1)\n• This causes more frequent collisions with electrons, reducing drift velocity and increasing resistance (1)\n• In a semiconductor: increasing temperature frees more charge carriers from bonds (1)\n• The increase in number density of charge carriers outweighs increased collisions, so resistance decreases (1)' },
      { q: 'State the relationship between charge, current, and the number of charge carriers passing a point.', marks: 1, markScheme: '• Q = nqt where n is number of carriers, q is charge per carrier; and I = Q/t = nq/t, or I = nAve for a conductor (1)' },
      { q: 'Calculate the resistance per unit length of a wire of resistivity 5.0 × 10⁻⁷ Ω m and cross-sectional area 1.0 × 10⁻⁶ m².', marks: 2, markScheme: '• R/L = ρ/A = 5.0 × 10⁻⁷ / 1.0 × 10⁻⁶ (1)\n• = 0.50 Ω m⁻¹ (1)' },
      { q: 'A potential divider uses a 10 kΩ potentiometer connected to a 5.0 V supply. The slider is set at 60% from the bottom. Calculate the output voltage.', marks: 1, markScheme: '• V_out = 0.60 × 5.0 = 3.0 V (1)' },
      { q: 'State what happens to the lost volts (Ir) as the external resistance is increased in a circuit with a battery.', marks: 2, markScheme: '• As R increases, I decreases (I = ε/(R+r)) (1)\n• Therefore Ir decreases, and the terminal PD (ε − Ir) increases, approaching ε (1)' }
    ]
  },
  '3.6': {
    name: 'Further Mechanics and Thermal Physics',
    questions: [
      { q: 'Define angular velocity and state its SI unit.', marks: 1, markScheme: '• ω = 2πf = 2π/T, unit: rad s⁻¹ (1)' },
      { q: 'State the expression for centripetal acceleration.', marks: 1, markScheme: '• a = v²/r = ω²r (1)' },
      { q: 'A car of mass 1200 kg travels around a circular bend of radius 50 m at 15 m s⁻¹. Calculate the centripetal force required.', marks: 2, markScheme: '• F = mv²/r = 1200 × 15² / 50 (1)\n• F = 5400 N (1)' },
      { q: 'Explain why an object moving in a circle at constant speed is accelerating.', marks: 2, markScheme: '• Although the speed is constant, the direction of velocity is continuously changing (1)\n• A change in velocity (even if only direction) constitutes an acceleration, directed towards the centre (1)' },
      { q: 'A satellite orbits the Earth at a radius of 7000 km. The mass of the Earth is 6.0 × 10²⁴ kg. Calculate its orbital period. (G = 6.67 × 10⁻¹¹ N m² kg⁻²)', marks: 3, markScheme: '• Gravitational force provides centripetal force: GMm/r² = mω²r, so ω² = GM/r³ (1)\n• ω = √(6.67 × 10⁻¹¹ × 6.0 × 10²⁴ / (7.0 × 10⁶)³) = 1.08 × 10⁻³ rad s⁻¹ (1)\n• T = 2π/ω = 5820 s ≈ 97 minutes (1)' },
      { q: 'Define simple harmonic motion (SHM).', marks: 2, markScheme: '• Oscillatory motion where the acceleration is proportional to the displacement (1)\n• And always directed towards the equilibrium position: a = −ω²x (1)' },
      { q: 'State the defining equation for SHM.', marks: 1, markScheme: '• a = −ω²x (1)' },
      { q: 'Write expressions for displacement, velocity, and acceleration of a body undergoing SHM.', marks: 3, markScheme: '• x = A cos(ωt) or x = A sin(ωt) (1)\n• v = −Aω sin(ωt) or v = Aω cos(ωt) (1)\n• a = −Aω² cos(ωt) = −ω²x (1)' },
      { q: 'State the expressions for the maximum velocity and maximum acceleration in SHM.', marks: 2, markScheme: '• Maximum velocity: v_max = Aω (at equilibrium position) (1)\n• Maximum acceleration: a_max = Aω² (at maximum displacement) (1)' },
      { q: 'A mass on a spring oscillates with amplitude 0.10 m and frequency 2.0 Hz. Calculate the maximum velocity.', marks: 2, markScheme: '• ω = 2πf = 2π × 2.0 = 4π rad s⁻¹ (1)\n• v_max = Aω = 0.10 × 4π = 1.26 m s⁻¹ (1)' },
      { q: 'State the period of a simple pendulum in terms of its length and g.', marks: 1, markScheme: '• T = 2π√(L/g) (1)' },
      { q: 'State the period of a mass-spring system in terms of mass and spring constant.', marks: 1, markScheme: '• T = 2π√(m/k) (1)' },
      { q: 'A 0.50 kg mass attached to a spring of constant 200 N m⁻¹ undergoes SHM. Calculate the period and frequency.', marks: 2, markScheme: '• T = 2π√(m/k) = 2π√(0.50/200) = 2π × 0.050 = 0.314 s (1)\n• f = 1/T = 3.18 Hz (1)' },
      { q: 'Describe the energy changes during one complete oscillation of a mass on a spring.', marks: 3, markScheme: '• At maximum displacement: all energy is elastic potential energy, KE = 0 (1)\n• At equilibrium position: all energy is kinetic energy, PE = 0 (1)\n• Total energy remains constant (in the absence of damping); energy continuously converts between KE and PE (1)' },
      { q: 'Distinguish between free oscillations and forced oscillations.', marks: 2, markScheme: '• Free: oscillations at the natural frequency with no external driving force, amplitude gradually decreases (1)\n• Forced: oscillations driven by an external periodic force, system oscillates at the driving frequency (1)' },
      { q: 'Define resonance.', marks: 2, markScheme: '• Resonance occurs when the driving frequency equals the natural frequency of the system (1)\n• Maximum amplitude of oscillation is achieved, with maximum energy transfer from driver to system (1)' },
      { q: 'Describe what happens to the resonance peak when damping is increased.', marks: 3, markScheme: '• The maximum amplitude at resonance decreases (1)\n• The resonance peak becomes broader/wider (1)\n• The resonant frequency shifts slightly lower than the natural frequency (1)' },
      { q: 'Define light damping, heavy damping, and critical damping.', marks: 3, markScheme: '• Light damping: system oscillates with gradually decreasing amplitude (1)\n• Heavy (over) damping: system returns to equilibrium very slowly without oscillating (1)\n• Critical damping: system returns to equilibrium in the shortest possible time without oscillating (1)' },
      { q: 'Give one practical example where critical damping is desirable.', marks: 1, markScheme: '• Car suspension / shock absorbers / door closers / moving-coil galvanometers (1)' },
      { q: 'Define internal energy of a system.', marks: 2, markScheme: '• The sum of the kinetic energies and potential energies of all the molecules in the system (1)\n• Kinetic energy is due to random motion; potential energy is due to intermolecular forces (1)' },
      { q: 'State what is meant by specific heat capacity.', marks: 1, markScheme: '• The energy required to raise the temperature of 1 kg of a substance by 1 K (or 1°C): Q = mcΔθ (1)' },
      { q: 'Calculate the energy needed to heat 2.0 kg of water from 20°C to 100°C. (c_water = 4200 J kg⁻¹ K⁻¹)', marks: 2, markScheme: '• Q = mcΔθ = 2.0 × 4200 × (100 − 20) (1)\n• Q = 672 000 J = 672 kJ (1)' },
      { q: 'Define specific latent heat of fusion.', marks: 1, markScheme: '• The energy required to change 1 kg of a substance from solid to liquid at constant temperature: Q = mL (1)' },
      { q: 'Define specific latent heat of vaporisation.', marks: 1, markScheme: '• The energy required to change 1 kg of a substance from liquid to gas at constant temperature (1)' },
      { q: 'Explain why latent heat is absorbed during melting but the temperature does not change.', marks: 3, markScheme: '• Energy is used to break intermolecular bonds / overcome intermolecular forces (1)\n• This increases the potential energy of the molecules (1)\n• The kinetic energy of the molecules does not change, so the temperature stays constant (1)' },
      { q: 'State Boyle\'s law.', marks: 1, markScheme: '• At constant temperature, the pressure of a fixed mass of gas is inversely proportional to its volume: pV = constant (1)' },
      { q: 'State Charles\'s law.', marks: 1, markScheme: '• At constant pressure, the volume of a fixed mass of gas is directly proportional to its absolute temperature: V/T = constant (1)' },
      { q: 'State the pressure law (Gay-Lussac\'s law).', marks: 1, markScheme: '• At constant volume, the pressure of a fixed mass of gas is directly proportional to its absolute temperature: p/T = constant (1)' },
      { q: 'Write the ideal gas equation and define each term.', marks: 2, markScheme: '• pV = nRT or pV = NkT (1)\n• p = pressure, V = volume, n = number of moles, R = molar gas constant, T = absolute temperature, N = number of molecules, k = Boltzmann constant (1)' },
      { q: 'A gas occupies 0.020 m³ at 1.0 × 10⁵ Pa and 300 K. It is heated to 600 K at constant volume. Calculate the new pressure.', marks: 2, markScheme: '• p₁/T₁ = p₂/T₂ (constant volume) → p₂ = p₁ × T₂/T₁ (1)\n• p₂ = 1.0 × 10⁵ × 600/300 = 2.0 × 10⁵ Pa (1)' },
      { q: 'Calculate the number of moles in 0.050 m³ of an ideal gas at 1.5 × 10⁵ Pa and 350 K. (R = 8.31 J mol⁻¹ K⁻¹)', marks: 2, markScheme: '• n = pV/RT = (1.5 × 10⁵ × 0.050) / (8.31 × 350) (1)\n• n = 2.58 mol (1)' },
      { q: 'State the assumptions of the kinetic theory of ideal gases.', marks: 4, markScheme: '• Molecules are point particles with negligible volume compared to the container (1)\n• No intermolecular forces except during collisions (1)\n• Collisions between molecules and with walls are perfectly elastic (1)\n• Molecules move randomly with a range of speeds; time of collision is negligible compared to time between collisions (1)' },
      { q: 'State the equation relating the pressure of an ideal gas to the mean square speed of its molecules.', marks: 1, markScheme: '• pV = ⅓Nm<c²> where N is number of molecules and <c²> is mean square speed (1)' },
      { q: 'Derive the relationship between the average kinetic energy of a gas molecule and absolute temperature.', marks: 3, markScheme: '• From pV = ⅓Nm<c²> and pV = NkT (1)\n• ⅓m<c²> = kT (1)\n• Therefore ½m<c²> = ³⁄₂kT, average KE per molecule is proportional to T (1)' },
      { q: 'Calculate the root mean square speed of nitrogen molecules at 300 K. (Molar mass of N₂ = 0.028 kg mol⁻¹, R = 8.31 J mol⁻¹ K⁻¹, Nₐ = 6.02 × 10²³)', marks: 3, markScheme: '• ½m<c²> = ³⁄₂kT, so <c²> = 3kT/m = 3RT/M (1)\n• <c²> = 3 × 8.31 × 300 / 0.028 = 2.67 × 10⁵ m² s⁻² (1)\n• c_rms = √(2.67 × 10⁵) = 517 m s⁻¹ (1)' },
      { q: 'An object undergoing SHM has a period of 0.50 s and amplitude 0.08 m. Calculate the displacement at t = 0.10 s if x = A at t = 0.', marks: 2, markScheme: '• ω = 2π/T = 2π/0.50 = 4π rad s⁻¹ (1)\n• x = A cos(ωt) = 0.08 × cos(4π × 0.10) = 0.08 × cos(0.4π) = 0.08 × 0.309 = 0.025 m (1)' },
      { q: 'A mass on a spring has total energy 0.20 J and amplitude 0.05 m. Calculate the spring constant.', marks: 2, markScheme: '• E = ½kA², so k = 2E/A² = 2 × 0.20 / 0.05² (1)\n• k = 160 N m⁻¹ (1)' },
      { q: 'Explain the Brownian motion experiment and what it provides evidence for.', marks: 3, markScheme: '• Smoke particles in a glass cell are observed under a microscope (1)\n• The particles show random, jerky movement in unpredictable directions (1)\n• This provides evidence for the random motion of air molecules which collide with the larger smoke particles (1)' },
      { q: 'Calculate the total kinetic energy of the molecules in 1.0 mol of an ideal gas at 400 K. (R = 8.31 J mol⁻¹ K⁻¹, Nₐ = 6.02 × 10²³, k = 1.38 × 10⁻²³ J K⁻¹)', marks: 2, markScheme: '• Total KE = N × ³⁄₂kT = Nₐ × ³⁄₂kT = ³⁄₂nRT (1)\n• = ³⁄₂ × 1.0 × 8.31 × 400 = 4986 J ≈ 5.0 kJ (1)' },
      { q: 'A 0.25 kg block of metal at 90°C is dropped into 0.50 kg of water at 20°C. The final temperature is 25°C. Calculate the specific heat capacity of the metal. (c_water = 4200 J kg⁻¹ K⁻¹)', marks: 3, markScheme: '• Heat lost by metal = heat gained by water (1)\n• m_m × c_m × ΔT_m = m_w × c_w × ΔT_w → 0.25 × c_m × 65 = 0.50 × 4200 × 5 (1)\n• c_m = 10500 / 16.25 = 646 J kg⁻¹ K⁻¹ (1)' },
      { q: 'A conical pendulum has a string of length 0.80 m making an angle of 30° with the vertical. Calculate the period of revolution. (g = 9.81 m s⁻²)', marks: 3, markScheme: '• Resolving: T cos θ = mg and T sin θ = mω²r, where r = L sin θ (1)\n• tan θ = ω²r/g = ω²L sin θ/g, so ω² = g tan θ/(L sin θ) = g/(L cos θ) (1)\n• ω = √(9.81/(0.80 × cos 30°)) = √(14.17) = 3.76 rad s⁻¹; T = 2π/ω = 1.67 s (1)' },
      { q: 'A gas at 2.0 × 10⁵ Pa occupies 0.010 m³. It expands at constant pressure to 0.030 m³. Calculate the work done by the gas.', marks: 2, markScheme: '• W = pΔV = 2.0 × 10⁵ × (0.030 − 0.010) (1)\n• W = 4000 J = 4.0 kJ (1)' },
      { q: 'State the first law of thermodynamics and define each term.', marks: 2, markScheme: '• Q = ΔU + W (1)\n• Q = heat supplied to the system, ΔU = increase in internal energy, W = work done by the system (1)' },
      { q: 'Explain why real gases deviate from ideal gas behaviour at high pressures and low temperatures.', marks: 3, markScheme: '• At high pressures, molecules are closer together so their volume is no longer negligible (1)\n• At low temperatures, molecules move more slowly so intermolecular forces become significant (1)\n• Both effects violate the assumptions of kinetic theory for an ideal gas (1)' },
      { q: 'Calculate the energy required to convert 0.30 kg of ice at 0°C to steam at 100°C. (L_f = 3.34 × 10⁵ J kg⁻¹, c_water = 4200 J kg⁻¹ K⁻¹, L_v = 2.26 × 10⁶ J kg⁻¹)', marks: 4, markScheme: '• Melting ice: Q₁ = mL_f = 0.30 × 3.34 × 10⁵ = 100 200 J (1)\n• Heating water: Q₂ = mcΔT = 0.30 × 4200 × 100 = 126 000 J (1)\n• Vaporising water: Q₃ = mL_v = 0.30 × 2.26 × 10⁶ = 678 000 J (1)\n• Total = 100 200 + 126 000 + 678 000 = 904 200 J ≈ 904 kJ (1)' },
      { q: 'Explain what is meant by the absolute zero of temperature.', marks: 2, markScheme: '• The lowest possible temperature, 0 K (−273.15°C) (1)\n• At which the molecules have minimum internal energy / zero kinetic energy (for an ideal gas) (1)' },
      { q: 'Sketch the variation of displacement, velocity, and acceleration with time for a body undergoing SHM. State the phase relationship between them.', marks: 4, markScheme: '• Displacement: sinusoidal curve (e.g. x = A sin ωt) (1)\n• Velocity: cosine curve, leading displacement by π/2 (90°) (1)\n• Acceleration: negative sine curve, in antiphase (π) with displacement (1)\n• v leads x by π/2; a leads v by π/2; a is π out of phase with x (1)' },
      { q: 'State what is meant by the Boltzmann constant and give its value.', marks: 1, markScheme: '• k = R/Nₐ = 1.38 × 10⁻²³ J K⁻¹; relates the average kinetic energy of molecules to temperature (1)' }
    ]
  },
  '3.7': {
    name: 'Fields and Their Consequences',
    questions: [
      { q: 'Define gravitational field strength at a point.', marks: 1, markScheme: '• The gravitational force per unit mass at that point: g = F/m (1)' },
      { q: 'State Newton\'s law of gravitation.', marks: 2, markScheme: '• The gravitational force between two point masses is proportional to the product of their masses and inversely proportional to the square of the distance between them (1)\n• F = −GMm/r² (1)' },
      { q: 'Calculate the gravitational field strength at the surface of the Earth. (M = 6.0 × 10²⁴ kg, R = 6.4 × 10⁶ m, G = 6.67 × 10⁻¹¹ N m² kg⁻²)', marks: 2, markScheme: '• g = GM/R² = (6.67 × 10⁻¹¹ × 6.0 × 10²⁴) / (6.4 × 10⁶)² (1)\n• g = 9.77 m s⁻² ≈ 9.8 m s⁻² (1)' },
      { q: 'Define gravitational potential at a point.', marks: 2, markScheme: '• The work done per unit mass in bringing a small test mass from infinity to that point (1)\n• V = −GM/r (always negative) (1)' },
      { q: 'Explain why gravitational potential is always negative.', marks: 2, markScheme: '• Potential is defined as zero at infinity (1)\n• Work must be done against the gravitational field to move a mass from the point to infinity, so the potential at any point is less than zero (1)' },
      { q: 'State the relationship between gravitational field strength and gravitational potential.', marks: 1, markScheme: '• g = −dV/dr (field strength is the negative potential gradient) (1)' },
      { q: 'Calculate the escape velocity from the surface of the Earth. (M = 6.0 × 10²⁴ kg, R = 6.4 × 10⁶ m, G = 6.67 × 10⁻¹¹ N m² kg⁻²)', marks: 3, markScheme: '• At escape velocity, KE = magnitude of GPE: ½mv² = GMm/R (1)\n• v = √(2GM/R) = √(2 × 6.67 × 10⁻¹¹ × 6.0 × 10²⁴ / 6.4 × 10⁶) (1)\n• v = 1.12 × 10⁴ m s⁻¹ ≈ 11.2 km s⁻¹ (1)' },
      { q: 'Explain what is meant by a geostationary orbit and state three of its properties.', marks: 4, markScheme: '• A geostationary orbit is one in which a satellite remains above the same point on the Earth\'s surface (1)\n• Period = 24 hours (same as Earth\'s rotation) (1)\n• Orbits in the equatorial plane (1)\n• Orbits from west to east (same direction as Earth\'s rotation) (1)' },
      { q: 'Define electric field strength at a point.', marks: 1, markScheme: '• The force per unit positive charge at that point: E = F/Q (1)' },
      { q: 'State Coulomb\'s law.', marks: 2, markScheme: '• The force between two point charges is proportional to the product of the charges and inversely proportional to the square of the distance between them (1)\n• F = Qq/(4πε₀r²) (1)' },
      { q: 'Calculate the electric field strength at a distance of 0.10 m from a point charge of 5.0 × 10⁻⁹ C. (ε₀ = 8.85 × 10⁻¹² F m⁻¹)', marks: 2, markScheme: '• E = Q/(4πε₀r²) = 5.0 × 10⁻⁹ / (4π × 8.85 × 10⁻¹² × 0.10²) (1)\n• E = 4500 V m⁻¹ ≈ 4.5 kV m⁻¹ (1)' },
      { q: 'State the expression for the electric potential at a distance r from a point charge Q.', marks: 1, markScheme: '• V = Q/(4πε₀r) (1)' },
      { q: 'Describe the electric field pattern between two parallel plates with a PD between them.', marks: 2, markScheme: '• Uniform field with equally spaced parallel lines perpendicular to the plates (1)\n• Field lines go from positive to negative plate; E = V/d (1)' },
      { q: 'Compare the gravitational and electric fields produced by a point mass and a point charge.', marks: 4, markScheme: '• Both follow inverse square laws (1)\n• Gravitational field is always attractive; electric field can be attractive or repulsive (1)\n• Gravitational potential is always negative; electric potential can be positive or negative (1)\n• Gravitational field strength: g = GM/r²; electric field strength: E = Q/(4πε₀r²) (1)' },
      { q: 'Define capacitance and state its SI unit.', marks: 1, markScheme: '• C = Q/V (charge stored per unit PD), unit: farad (F) (1)' },
      { q: 'Calculate the charge stored on a 47 μF capacitor charged to 12 V.', marks: 1, markScheme: '• Q = CV = 47 × 10⁻⁶ × 12 = 5.64 × 10⁻⁴ C = 0.56 mC (1)' },
      { q: 'State three expressions for the energy stored in a charged capacitor.', marks: 2, markScheme: '• E = ½QV = ½CV² = ½Q²/C (1)\n• All three equivalent forms (1)' },
      { q: 'Calculate the energy stored in a 100 μF capacitor charged to 20 V.', marks: 2, markScheme: '• E = ½CV² = ½ × 100 × 10⁻⁶ × 20² (1)\n• E = 0.020 J = 20 mJ (1)' },
      { q: 'State the expression for the combined capacitance of two capacitors in series.', marks: 1, markScheme: '• 1/C = 1/C₁ + 1/C₂ (1)' },
      { q: 'State the expression for the combined capacitance of two capacitors in parallel.', marks: 1, markScheme: '• C = C₁ + C₂ (1)' },
      { q: 'A 200 μF capacitor discharges through a 50 kΩ resistor. Calculate the time constant.', marks: 1, markScheme: '• τ = RC = 50 × 10³ × 200 × 10⁻⁶ = 10 s (1)' },
      { q: 'A capacitor of 100 μF is charged to 10 V and then discharges through a 20 kΩ resistor. Calculate the charge remaining after 3.0 s.', marks: 3, markScheme: '• Q₀ = CV = 100 × 10⁻⁶ × 10 = 1.0 × 10⁻³ C (1)\n• τ = RC = 20 × 10³ × 100 × 10⁻⁶ = 2.0 s (1)\n• Q = Q₀ e^(−t/τ) = 1.0 × 10⁻³ × e^(−3.0/2.0) = 1.0 × 10⁻³ × 0.223 = 2.23 × 10⁻⁴ C (1)' },
      { q: 'State the equation for exponential discharge of a capacitor.', marks: 1, markScheme: '• Q = Q₀ e^(−t/RC) or V = V₀ e^(−t/RC) or I = I₀ e^(−t/RC) (1)' },
      { q: 'Explain what the time constant of an RC circuit represents.', marks: 2, markScheme: '• τ = RC is the time taken for the charge (or voltage or current) to fall to 1/e (≈ 37%) of its initial value (1)\n• Or the time for charge to reach 63% of its final value during charging (1)' },
      { q: 'Define magnetic flux density (B) and state its SI unit.', marks: 1, markScheme: '• The force per unit length per unit current on a conductor carrying current at right angles to the field; unit: tesla (T) (1)' },
      { q: 'State the expression for the force on a current-carrying conductor in a magnetic field.', marks: 1, markScheme: '• F = BIL sin θ (1)' },
      { q: 'A wire of length 0.25 m carries a current of 3.0 A perpendicular to a magnetic field of flux density 0.40 T. Calculate the force on the wire.', marks: 1, markScheme: '• F = BIL = 0.40 × 3.0 × 0.25 = 0.30 N (1)' },
      { q: 'State the expression for the force on a charged particle moving in a magnetic field.', marks: 1, markScheme: '• F = BQv sin θ (1)' },
      { q: 'A proton moving at 5.0 × 10⁶ m s⁻¹ enters a magnetic field of 0.20 T perpendicular to its velocity. Calculate the radius of its circular path. (mₚ = 1.67 × 10⁻²⁷ kg, e = 1.60 × 10⁻¹⁹ C)', marks: 2, markScheme: '• BQv = mv²/r, so r = mv/(BQ) = (1.67 × 10⁻²⁷ × 5.0 × 10⁶) / (0.20 × 1.60 × 10⁻¹⁹) (1)\n• r = 0.261 m ≈ 0.26 m (1)' },
      { q: 'Define magnetic flux and state its SI unit.', marks: 1, markScheme: '• Φ = BA cos θ, where A is area and θ is angle between B and the normal to the area; unit: weber (Wb) (1)' },
      { q: 'State Faraday\'s law of electromagnetic induction.', marks: 2, markScheme: '• The magnitude of the induced EMF is proportional to (or equal to) the rate of change of magnetic flux linkage (1)\n• ε = −N dΦ/dt (1)' },
      { q: 'State Lenz\'s law.', marks: 1, markScheme: '• The direction of the induced EMF (or current) is such that it opposes the change producing it (1)' },
      { q: 'A coil of 200 turns and area 0.010 m² is in a magnetic field that changes from 0.50 T to 0.10 T in 0.20 s. Calculate the induced EMF.', marks: 2, markScheme: '• ε = NΔΦ/Δt = N × A × ΔB/Δt = 200 × 0.010 × (0.50 − 0.10)/0.20 (1)\n• ε = 200 × 0.010 × 2.0 = 4.0 V (1)' },
      { q: 'Explain how an EMF is generated in an AC generator.', marks: 3, markScheme: '• A coil rotates in a uniform magnetic field (1)\n• The flux linkage through the coil changes sinusoidally as the coil rotates (1)\n• By Faraday\'s law, the rate of change of flux linkage induces an alternating EMF (1)' },
      { q: 'State the relationship between the peak voltage and the RMS voltage for an AC supply.', marks: 1, markScheme: '• V_rms = V₀/√2 (1)' },
      { q: 'The mains supply in the UK has an RMS voltage of 230 V. Calculate the peak voltage.', marks: 1, markScheme: '• V₀ = V_rms × √2 = 230 × 1.414 = 325 V (1)' },
      { q: 'State the equation for the EMF of an ideal transformer.', marks: 1, markScheme: '• V_s/V_p = N_s/N_p (1)' },
      { q: 'A transformer with 500 primary turns and 50 secondary turns is connected to a 230 V AC supply. Calculate the output voltage.', marks: 2, markScheme: '• V_s = V_p × N_s/N_p = 230 × 50/500 (1)\n• V_s = 23 V (1)' },
      { q: 'Explain why transformers only work with AC and not DC.', marks: 2, markScheme: '• AC produces a continuously changing current in the primary coil (1)\n• This creates a changing magnetic flux in the core which induces an EMF in the secondary coil; DC would produce a constant flux so no induced EMF (1)' },
      { q: 'Explain why electrical energy is transmitted at high voltage.', marks: 3, markScheme: '• Power loss in cables = I²R (1)\n• For a given power P = IV, increasing V means decreasing I (1)\n• Lower current means less power lost as heat in the transmission cables (I²R is reduced) (1)' },
      { q: 'A parallel plate capacitor has plates of area 0.020 m² separated by 2.0 mm. The space between the plates is filled with a dielectric of relative permittivity 5.0. Calculate the capacitance. (ε₀ = 8.85 × 10⁻¹² F m⁻¹)', marks: 2, markScheme: '• C = ε₀εᵣA/d = 8.85 × 10⁻¹² × 5.0 × 0.020 / (2.0 × 10⁻³) (1)\n• C = 4.43 × 10⁻¹⁰ F = 0.44 nF (1)' },
      { q: 'Calculate the gravitational potential energy of a 500 kg satellite in orbit at a height of 400 km above the Earth\'s surface. (M = 6.0 × 10²⁴ kg, R = 6.4 × 10⁶ m, G = 6.67 × 10⁻¹¹ N m² kg⁻²)', marks: 2, markScheme: '• r = R + h = 6.4 × 10⁶ + 0.4 × 10⁶ = 6.8 × 10⁶ m; E = −GMm/r (1)\n• E = −(6.67 × 10⁻¹¹ × 6.0 × 10²⁴ × 500) / (6.8 × 10⁶) = −2.94 × 10¹⁰ J (1)' },
      { q: 'Derive the expression for the orbital speed of a satellite at radius r from the centre of a planet of mass M.', marks: 2, markScheme: '• Gravitational force provides centripetal force: GMm/r² = mv²/r (1)\n• v = √(GM/r) (1)' },
      { q: 'Explain what is meant by an equipotential surface and state the relationship between equipotentials and field lines.', marks: 2, markScheme: '• An equipotential surface is a surface on which every point is at the same potential (1)\n• Equipotential surfaces are always perpendicular to field lines; no work is done moving along an equipotential (1)' },
      { q: 'Describe an experiment to investigate the charge and discharge of a capacitor through a resistor.', marks: 4, markScheme: '• Connect capacitor in series with resistor and a switch, with a voltmeter across the capacitor and a data logger or stopwatch (1)\n• Charge: close switch to supply, record voltage across capacitor at regular time intervals (1)\n• Discharge: disconnect supply and close switch to allow capacitor to discharge through resistor (1)\n• Plot V (or ln V) against t; for discharge, ln V vs t gives a straight line with gradient −1/RC (1)' },
      { q: 'Explain why a charged particle moving parallel to a magnetic field experiences no force.', marks: 2, markScheme: '• F = BQv sin θ, where θ is the angle between the velocity and the field (1)\n• When the particle moves parallel to B, θ = 0° so sin θ = 0 and F = 0 (1)' }
    ]
  },
  '3.8': {
    name: 'Nuclear Physics',
    questions: [
      { q: 'State what is meant by the term "radioactive decay".', marks: 2, markScheme: '• The spontaneous and random emission of radiation from an unstable nucleus (1)\n• The nucleus changes to become more stable (1)' },
      { q: 'State the nature and properties of alpha (α) radiation.', marks: 3, markScheme: '• Alpha particle is a helium nucleus (2 protons, 2 neutrons) / ⁴₂He (1)\n• Strongly ionising, short range in air (~5 cm) (1)\n• Stopped by paper or a few cm of air (1)' },
      { q: 'State the nature and properties of beta-minus (β⁻) radiation.', marks: 3, markScheme: '• Beta-minus particle is a high-energy electron emitted from the nucleus (1)\n• Moderately ionising, range of several metres in air (1)\n• Stopped by a few mm of aluminium (1)' },
      { q: 'State the nature and properties of gamma (γ) radiation.', marks: 3, markScheme: '• Gamma ray is a high-frequency electromagnetic wave / photon (1)\n• Weakly ionising, very long range in air (1)\n• Intensity reduced by several cm of lead or metres of concrete (1)' },
      { q: 'Write the nuclear equation for the alpha decay of uranium-238.', marks: 2, markScheme: '• ²³⁸₉₂U → ²³⁴₉₀Th + ⁴₂He (1)\n• Both mass number and atomic number are conserved (1)' },
      { q: 'Write the nuclear equation for the beta-minus decay of carbon-14.', marks: 2, markScheme: '• ¹⁴₆C → ¹⁴₇N + ⁰₋₁e + ν̄ₑ (1)\n• An antineutrino is also emitted (1)' },
      { q: 'Define the term "half-life".', marks: 1, markScheme: '• The time taken for the number of radioactive nuclei (or the activity) to decrease to half its original value (1)' },
      { q: 'A radioactive isotope has a half-life of 6 hours. A sample initially contains 1.0 × 10⁶ atoms. Calculate the number remaining after 18 hours.', marks: 2, markScheme: '• Number of half-lives = 18/6 = 3 (1)\n• N = 1.0 × 10⁶ × (½)³ = 1.0 × 10⁶ / 8 = 1.25 × 10⁵ (1)' },
      { q: 'State the relationship between half-life and decay constant.', marks: 1, markScheme: '• T₁/₂ = ln 2 / λ = 0.693 / λ (1)' },
      { q: 'Define activity and state its SI unit.', marks: 1, markScheme: '• Activity A = λN (rate of decay / number of disintegrations per second), unit: becquerel (Bq) (1)' },
      { q: 'A sample has an activity of 400 Bq. Its half-life is 8.0 days. Calculate the decay constant and the number of undecayed nuclei.', marks: 3, markScheme: '• λ = ln 2 / T₁/₂ = 0.693 / (8.0 × 86400) = 1.00 × 10⁻⁶ s⁻¹ (1)\n• N = A/λ = 400 / 1.00 × 10⁻⁶ (1)\n• N = 4.0 × 10⁸ (1)' },
      { q: 'State the exponential decay equation for the number of radioactive nuclei.', marks: 1, markScheme: '• N = N₀ e^(−λt) (1)' },
      { q: 'Explain what is meant by "random" and "spontaneous" in the context of radioactive decay.', marks: 2, markScheme: '• Random: it is impossible to predict which particular nucleus will decay next / the probability of decay is the same for each nucleus (1)\n• Spontaneous: the decay is not affected by external conditions such as temperature or pressure (1)' },
      { q: 'Describe an experiment to determine the half-life of a radioactive isotope with a half-life of a few minutes.', marks: 4, markScheme: '• Measure background radiation count rate first without the source (1)\n• Place the source near a detector (e.g. Geiger-Muller tube and counter) and record the count rate at regular time intervals (1)\n• Subtract the background count rate from each reading to get corrected count rate (1)\n• Plot corrected count rate (or ln of count rate) against time; half-life read from graph (or gradient = −λ) (1)' },
      { q: 'Explain how the random nature of radioactive decay is confirmed experimentally.', marks: 2, markScheme: '• Repeated count rate measurements over the same time interval show fluctuations (1)\n• The count rates follow a Poisson distribution / the standard deviation is approximately equal to the square root of the mean count (1)' },
      { q: 'Define the term "nuclear radius" and state how it depends on nucleon number A.', marks: 2, markScheme: '• The radius of a nucleus (1)\n• r = r₀ A^(1/3), where r₀ ≈ 1.2–1.4 fm (1)' },
      { q: 'Calculate the radius of a nucleus of iron-56. (r₀ = 1.2 fm)', marks: 2, markScheme: '• r = r₀ A^(1/3) = 1.2 × 56^(1/3) (1)\n• r = 1.2 × 3.83 = 4.6 fm (1)' },
      { q: 'Show that the density of nuclear matter is approximately constant regardless of the nucleon number.', marks: 3, markScheme: '• V = (4/3)πr³ = (4/3)π(r₀A^(1/3))³ = (4/3)πr₀³A (1)\n• Mass ≈ A × mₙ (where mₙ is nucleon mass) (1)\n• ρ = mass/volume = Amₙ / ((4/3)πr₀³A) = mₙ / ((4/3)πr₀³), which is independent of A (1)' },
      { q: 'Explain how electron diffraction experiments are used to estimate nuclear radii.', marks: 3, markScheme: '• High-energy electrons are fired at nuclei and the diffraction pattern is observed (1)\n• The first minimum occurs at sin θ ≈ 1.22λ/2R, where R is the nuclear radius (1)\n• The de Broglie wavelength must be comparable to the nuclear size (~10⁻¹⁵ m), requiring very high energies (1)' },
      { q: 'Define mass defect.', marks: 2, markScheme: '• The difference between the total mass of the individual nucleons and the mass of the nucleus (1)\n• Δm = Zmₚ + (A−Z)mₙ − M_nucleus (1)' },
      { q: 'Define binding energy.', marks: 1, markScheme: '• The energy required to completely separate all nucleons in a nucleus to infinity / the energy equivalent of the mass defect: E = Δmc² (1)' },
      { q: 'Define binding energy per nucleon and explain its significance.', marks: 2, markScheme: '• Binding energy per nucleon = total binding energy / number of nucleons (A) (1)\n• It is a measure of the stability of a nucleus; higher values mean more stable nuclei (1)' },
      { q: 'Calculate the binding energy of helium-4 given: mass of He-4 = 4.00260 u, mass of proton = 1.00728 u, mass of neutron = 1.00866 u. (1 u = 931.5 MeV)', marks: 3, markScheme: '• Mass of separate nucleons = 2(1.00728) + 2(1.00866) = 4.03188 u (1)\n• Mass defect = 4.03188 − 4.00260 = 0.02928 u (1)\n• Binding energy = 0.02928 × 931.5 = 27.3 MeV (1)' },
      { q: 'Sketch the graph of binding energy per nucleon against nucleon number and identify the most stable region.', marks: 3, markScheme: '• Graph rises steeply for low A, peaks around A = 56 (iron/nickel region) (1)\n• Then gradually decreases for larger A (1)\n• Iron-56 region has highest binding energy per nucleon and is the most stable (1)' },
      { q: 'Explain how the binding energy per nucleon curve accounts for energy release in fission.', marks: 3, markScheme: '• In fission, a heavy nucleus splits into two medium-mass nuclei (1)\n• The products have a higher binding energy per nucleon than the original nucleus (1)\n• The increase in total binding energy is released as kinetic energy of the products (1)' },
      { q: 'Explain how the binding energy per nucleon curve accounts for energy release in fusion.', marks: 3, markScheme: '• In fusion, two light nuclei combine to form a heavier nucleus (1)\n• The product has a higher binding energy per nucleon than the original nuclei (1)\n• The increase in total binding energy is released as kinetic energy / radiation (1)' },
      { q: 'Define nuclear fission and give one example.', marks: 2, markScheme: '• The splitting of a heavy nucleus into two lighter nuclei, usually triggered by neutron absorption (1)\n• Example: ²³⁵U + n → ¹⁴¹Ba + ⁹²Kr + 3n (or similar) (1)' },
      { q: 'Define nuclear fusion and give one example.', marks: 2, markScheme: '• The joining of two light nuclei to form a heavier nucleus, releasing energy (1)\n• Example: ²H + ³H → ⁴He + n (or similar) (1)' },
      { q: 'Explain why nuclear fusion requires extremely high temperatures.', marks: 3, markScheme: '• Both nuclei are positively charged and repel each other (Coulomb repulsion) (1)\n• At very high temperatures, nuclei have sufficient kinetic energy to overcome the electrostatic barrier (1)\n• They must get close enough (within ~10⁻¹⁵ m) for the strong nuclear force to take over (1)' },
      { q: 'A fission reaction releases 200 MeV per event. Calculate the energy released in joules from the fission of 1.0 kg of uranium-235. (Nₐ = 6.02 × 10²³, molar mass of U-235 = 0.235 kg mol⁻¹, 1 eV = 1.60 × 10⁻¹⁹ J)', marks: 3, markScheme: '• Number of atoms = (1.0/0.235) × 6.02 × 10²³ = 2.56 × 10²⁴ (1)\n• Total energy = 2.56 × 10²⁴ × 200 × 10⁶ × 1.60 × 10⁻¹⁹ (1)\n• = 8.19 × 10¹³ J ≈ 8.2 × 10¹³ J (1)' },
      { q: 'Explain the role of the moderator in a nuclear fission reactor.', marks: 2, markScheme: '• The moderator slows down fast neutrons to thermal energies (1)\n• Slow (thermal) neutrons are more likely to be captured by U-235 nuclei to sustain the chain reaction (1)' },
      { q: 'Explain the role of control rods in a nuclear fission reactor.', marks: 2, markScheme: '• Control rods absorb neutrons (1)\n• They are raised or lowered to control the rate of the chain reaction / maintain a steady rate of fission (1)' },
      { q: 'Explain what is meant by a chain reaction in nuclear fission.', marks: 2, markScheme: '• Each fission event releases neutrons that can go on to cause further fission events (1)\n• If on average one neutron from each fission causes another fission, the reaction is self-sustaining / critical (1)' },
      { q: 'A radioactive source has an initial activity of 8000 Bq. After 40 minutes the activity is 500 Bq. Calculate the half-life.', marks: 3, markScheme: '• A = A₀ e^(−λt), so 500 = 8000 e^(−λ×2400) (1)\n• e^(−2400λ) = 500/8000 = 0.0625, so −2400λ = ln(0.0625) = −2.773 (1)\n• λ = 1.155 × 10⁻³ s⁻¹; T₁/₂ = 0.693/λ = 600 s = 10 minutes (1)' },
      { q: 'Carbon dating uses the decay of carbon-14 (half-life 5730 years). A sample of wood has an activity that is 25% of the activity of living wood. Estimate the age of the sample.', marks: 3, markScheme: '• 25% = (½)ⁿ where n = number of half-lives, so n = 2 (1)\n• Age = 2 × 5730 = 11 460 years (1)\n• ≈ 11 500 years (1)' },
      { q: 'Describe the processes that occur when a slow neutron is absorbed by a uranium-235 nucleus.', marks: 3, markScheme: '• The U-235 nucleus absorbs the neutron and becomes U-236 in an excited state (1)\n• The U-236 nucleus is unstable and splits (fissions) into two smaller daughter nuclei (1)\n• Two or three fast neutrons and gamma radiation are also released, along with a large amount of kinetic energy (1)' },
      { q: 'Calculate the energy released when tritium (³H) and deuterium (²H) fuse to form helium-4 and a neutron. Masses: ²H = 2.01410 u, ³H = 3.01605 u, ⁴He = 4.00260 u, n = 1.00866 u. (1 u = 931.5 MeV)', marks: 3, markScheme: '• Mass before = 2.01410 + 3.01605 = 5.03015 u (1)\n• Mass after = 4.00260 + 1.00866 = 5.01126 u (1)\n• Energy released = (5.03015 − 5.01126) × 931.5 = 0.01889 × 931.5 = 17.6 MeV (1)' },
      { q: 'Explain the concept of induced fission and how it differs from spontaneous fission.', marks: 2, markScheme: '• Induced fission occurs when a nucleus absorbs a neutron and becomes unstable, then splits (1)\n• Spontaneous fission occurs naturally without any external trigger, but is extremely rare for most isotopes (1)' },
      { q: 'A hospital radioactive source has an activity of 2.0 × 10⁹ Bq. The half-life is 8.0 days. Calculate the activity after 24 days.', marks: 2, markScheme: '• Number of half-lives = 24/8.0 = 3 (1)\n• A = 2.0 × 10⁹ × (½)³ = 2.5 × 10⁸ Bq (1)' },
      { q: 'Explain why nuclear waste from fission reactors is a significant problem.', marks: 3, markScheme: '• Fission products are highly radioactive with a range of half-lives, some very long (1)\n• They emit harmful radiation that can cause biological damage (1)\n• Safe storage for potentially thousands of years is required, which is technically and economically challenging (1)' },
      { q: 'A sample contains 5.0 × 10²⁰ atoms of a radioactive isotope with decay constant 2.0 × 10⁻⁴ s⁻¹. Calculate the initial activity and the activity after 1 hour.', marks: 3, markScheme: '• A₀ = λN = 2.0 × 10⁻⁴ × 5.0 × 10²⁰ = 1.0 × 10¹⁷ Bq (1)\n• A = A₀ e^(−λt) = 1.0 × 10¹⁷ × e^(−2.0 × 10⁻⁴ × 3600) (1)\n• A = 1.0 × 10¹⁷ × e^(−0.72) = 1.0 × 10¹⁷ × 0.487 = 4.87 × 10¹⁶ Bq (1)' },
      { q: 'Explain the significance of E = mc² in nuclear physics.', marks: 3, markScheme: '• Mass and energy are equivalent and interchangeable (1)\n• In nuclear reactions, a small loss of mass results in a large release of energy due to c² being very large (1)\n• This accounts for the energy released in fission and fusion reactions (1)' },
      { q: 'State two safety precautions that should be taken when handling radioactive sources in a laboratory.', marks: 2, markScheme: '• Keep sources at arm\'s length / use tongs, minimise exposure time (1)\n• Store in lead-lined containers when not in use / do not point sources at people (1)' },
      { q: 'Explain why the neutrons released in fission need to be moderated before they can cause further fission of U-235.', marks: 2, markScheme: '• Neutrons released from fission have very high kinetic energy (fast neutrons) (1)\n• U-235 has a much higher probability of capturing slow (thermal) neutrons, so moderation is needed to sustain the chain reaction (1)' },
      { q: 'Calculate the nuclear density given r₀ = 1.2 fm and nucleon mass = 1.67 × 10⁻²⁷ kg.', marks: 3, markScheme: '• Volume of one nucleon region = (4/3)πr₀³ = (4/3)π(1.2 × 10⁻¹⁵)³ = 7.24 × 10⁻⁴⁵ m³ (1)\n• ρ = m/V = 1.67 × 10⁻²⁷ / 7.24 × 10⁻⁴⁵ (1)\n• ρ = 2.3 × 10¹⁷ kg m⁻³ (1)' }
    ]
  }
};